54	class ddc_block_control_impl : public ddc_block_control
55	{
56	public:
57	    RFNOC_BLOCK_CONSTRUCTOR(ddc_block_control)
58	    , _ddc_reg_iface(*this, 0, REG_CHAN_OFFSET),
59	        _fpga_compat(regs().peek32(RB_COMPAT_NUM)),
60	        _num_halfbands(regs().peek32(RB_NUM_HB)),
61	        _cic_max_decim(regs().peek32(RB_CIC_MAX_DECIM)),
62	        _residual_scaling(get_num_input_ports(), DEFAULT_SCALING)
63	    {
64	        UHD_ASSERT_THROW(get_num_input_ports() == get_num_output_ports());
65	        UHD_ASSERT_THROW(_cic_max_decim > 0 && _cic_max_decim <= 0xFF);
66	        uhd::assert_fpga_compat(MAJOR_COMPAT,
67	            MINOR_COMPAT,
68	            _fpga_compat,
69	            get_unique_id(),
70	            get_unique_id(),
71	            false /* Let it slide if minors mismatch */
72	        );
73	        RFNOC_LOG_DEBUG("Loading DDC with " << _num_halfbands
74	                                            << " halfbands and "
75	                                               "max CIC decimation "
76	                                            << _cic_max_decim);
77	        // This line is not strictly necessary, as ONE_TO_ONE is the default.
78	        // We set it make it explicit how this block works.
79	        set_mtu_forwarding_policy(forwarding_policy_t::ONE_TO_ONE);
80	
81	        // Load list of valid decimation values
82	        std::set<size_t> decims{1}; // 1 is always a valid decimation
83	        for (size_t hb = 0; hb <= _num_halfbands; hb++) {
84	            for (size_t cic_decim = 1; cic_decim <= _cic_max_decim; cic_decim++) {
85	                decims.insert((1 << hb) * cic_decim);
86	            }
87	        }
88	        for (size_t decim : decims) {
89	            _valid_decims.push_back(uhd::range_t(double(decim)));
90	        }
91	
92	        // Initialize properties. It is very important to first reserve the
93	        // space, because we use push_back() further down, and properties must
94	        // not change their base address after registration and resolver
95	        // creation.
96	        _samp_rate_in.reserve(get_num_ports());
97	        _samp_rate_out.reserve(get_num_ports());
98	        _scaling_in.reserve(get_num_ports());
99	        _scaling_out.reserve(get_num_ports());
100	        _decim.reserve(get_num_ports());
101	        _freq.reserve(get_num_ports());
102	        _type_in.reserve(get_num_ports());
103	        _type_out.reserve(get_num_ports());
104	        for (size_t chan = 0; chan < get_num_ports(); chan++) {
105	            _register_props(chan);
106	        }
107	        register_issue_stream_cmd();
108	        register_issue_tune_request();
109	    }
