111	    double set_freq(const double freq,
112	        const size_t chan,
113	        const boost::optional<uhd::time_spec_t> time) override
114	    {
115	        // Store the current command time so we can restore it later
116	        auto prev_cmd_time = get_command_time(chan);
117	        if (time) {
118	            set_command_time(time.get(), chan);
119	        }
120	        // This will trigger property propagation:
121	        set_property<double>("freq", freq, chan);
122	        set_command_time(prev_cmd_time, chan);
123	        return get_freq(chan);
124	    }
125	
126	    double get_freq(const size_t chan) const override
127	    {
128	        return _freq.at(chan).get();
129	    }
130	
131	    uhd::freq_range_t get_frequency_range(const size_t chan) const override
132	    {
133	        const double input_rate = get_input_rate(chan);
134	        // TODO add steps
135	        return uhd::freq_range_t(-input_rate / 2, input_rate / 2);
136	    }
