138	    double get_input_rate(const size_t chan) const override
139	    {
140	        return _samp_rate_in.at(chan).is_valid() ? _samp_rate_in.at(chan).get() : 1.0;
141	    }
142	
143	    void set_input_rate(const double rate, const size_t chan) override
144	    {
145	        set_property<double>("samp_rate", rate, {res_source_info::INPUT_EDGE, chan});
146	    }
147	
148	    double get_output_rate(const size_t chan) const override
149	    {
150	        return _samp_rate_out.at(chan).is_valid() ? _samp_rate_out.at(chan).get() : 1.0;
151	    }
152	
153	    uhd::meta_range_t get_output_rates(const size_t chan) const override
154	    {
155	        uhd::meta_range_t result;
156	        if (!_samp_rate_in.at(chan).is_valid()) {
157	            result.push_back(uhd::range_t(1.0));
158	            return result;
159	        }
160	        const double input_rate = _samp_rate_in.at(chan).get();
161	        // The decimations are stored in order (from smallest to biggest), so
162	        // iterate in reverse order so we can add rates from smallest to biggest
163	        for (auto it = _valid_decims.rbegin(); it != _valid_decims.rend(); ++it) {
164	            result.push_back(uhd::range_t(input_rate / it->start()));
165	        }
166	        return result;
167	    }
168	
169	    double set_output_rate(const double rate, const size_t chan) override
170	    {
171	        if (_samp_rate_in.at(chan).is_valid()) {
172	            const int coerced_decim = coerce_decim(get_input_rate(chan) / rate);
173	            set_property<int>("decim", coerced_decim, chan);
174	        } else {
175	            RFNOC_LOG_DEBUG("Property samp_rate@"
176	                            << chan << " is not valid, attempting to set output rate "
177	                            << (rate / 1e6) << " Msps via the edge property.");
178	            set_property<double>("samp_rate", rate, {res_source_info::OUTPUT_EDGE, chan});
179	        }
180	        return _samp_rate_out.at(chan).get();
181	    }
182	
183	    // Somewhat counter-intuitively, we post a stream command as a message to
184	    // ourselves. That's because it's easier to re-use the message handler than
185	    // it is to reuse the issue_stream_cmd() API call, because this API call
186	    // will always be forwarded to the upstream block, whereas the message
187	    // handler goes both ways.
188	    // This way, calling issue_stream_cmd() is the same as posting a message to
189	    // our output port.
190	    void issue_stream_cmd(const uhd::stream_cmd_t& stream_cmd, const size_t port) override
191	    {
192	        RFNOC_LOG_TRACE("issue_stream_cmd(stream_mode=" << char(stream_cmd.stream_mode)
193	                                                        << ", port=" << port);
194	        res_source_info dst_edge{res_source_info::OUTPUT_EDGE, port};
195	        auto new_action        = stream_cmd_action_info::make(stream_cmd.stream_mode);
196	        new_action->stream_cmd = stream_cmd;
197	        issue_stream_cmd_action_handler(dst_edge, new_action);
198	    }
