211	    /**************************************************************************
212	     * Initialization
213	     *************************************************************************/
214	    void _register_props(const size_t chan)
215	    {
216	        // Create actual properties and store them
217	        _samp_rate_in.push_back(
218	            property_t<double>(PROP_KEY_SAMP_RATE, {res_source_info::INPUT_EDGE, chan}));
219	        _samp_rate_out.push_back(
220	            property_t<double>(PROP_KEY_SAMP_RATE, {res_source_info::OUTPUT_EDGE, chan}));
221	        _scaling_in.push_back(
222	            property_t<double>(PROP_KEY_SCALING, {res_source_info::INPUT_EDGE, chan}));
223	        _scaling_out.push_back(
224	            property_t<double>(PROP_KEY_SCALING, {res_source_info::OUTPUT_EDGE, chan}));
225	        _decim.push_back(property_t<int>(
226	            PROP_KEY_DECIM, DEFAULT_DECIM, {res_source_info::USER, chan}));
227	        _freq.push_back(property_t<double>(
228	            PROP_KEY_FREQ, DEFAULT_FREQ, {res_source_info::USER, chan}));
229	        _type_in.emplace_back(property_t<std::string>(
230	            PROP_KEY_TYPE, IO_TYPE_SC16, {res_source_info::INPUT_EDGE, chan}));
231	        _type_out.emplace_back(property_t<std::string>(
232	            PROP_KEY_TYPE, IO_TYPE_SC16, {res_source_info::OUTPUT_EDGE, chan}));
233	        UHD_ASSERT_THROW(_samp_rate_in.size() == chan + 1);
234	        UHD_ASSERT_THROW(_samp_rate_out.size() == chan + 1);
235	        UHD_ASSERT_THROW(_scaling_in.size() == chan + 1);
236	        UHD_ASSERT_THROW(_scaling_out.size() == chan + 1);
237	        UHD_ASSERT_THROW(_decim.size() == chan + 1);
238	        UHD_ASSERT_THROW(_freq.size() == chan + 1);
239	        UHD_ASSERT_THROW(_type_in.size() == chan + 1);
240	        UHD_ASSERT_THROW(_type_out.size() == chan + 1);
241	
242	        // give us some shorthands for the rest of this function
243	        property_t<double>* samp_rate_in  = &_samp_rate_in.back();
244	        property_t<double>* samp_rate_out = &_samp_rate_out.back();
245	        property_t<double>* scaling_in    = &_scaling_in.back();
246	        property_t<double>* scaling_out   = &_scaling_out.back();
247	        property_t<int>* decim            = &_decim.back();
248	        property_t<double>* freq          = &_freq.back();
249	        property_t<std::string>* type_in  = &_type_in.back();
250	        property_t<std::string>* type_out = &_type_out.back();
251	
252	        // register them
253	        register_property(samp_rate_in);
254	        register_property(samp_rate_out);
255	        register_property(scaling_in);
256	        register_property(scaling_out);
257	        register_property(decim);
258	        register_property(freq);
259	        register_property(type_in);
260	        register_property(type_out);
261	
262	        /**********************************************************************
263	         * Add resolvers
264	         *********************************************************************/
265	        // Resolver for _decim: this gets executed when the user directly
266	        // modifies _decim. the desired behaviour is to coerce it first, then
267	        // keep the input rate constant, and re-calculate the output rate.
268	        add_property_resolver({decim},
269	            {decim, samp_rate_out, samp_rate_in, scaling_in},
270	            [this,
271	                chan,
272	                &decim         = *decim,
273	                &samp_rate_out = *samp_rate_out,
274	                &samp_rate_in  = *samp_rate_in,
275	                &scaling_in    = *scaling_in]() {
276	                RFNOC_LOG_TRACE("Calling resolver for `decim'@" << chan);
277	                decim = coerce_decim(double(decim.get()));
278	                if (decim.is_dirty()) {
279	                    set_decim(decim.get(), chan);
280	                }
281	                if (samp_rate_in.is_valid()) {
282	                    samp_rate_out = samp_rate_in.get() / decim.get();
283	                } else if (samp_rate_out.is_valid()) {
284	                    samp_rate_in = samp_rate_out.get() * decim.get();
285	                }
286	                if (scaling_in.is_valid()) {
287	                    scaling_in.force_dirty();
288	                }
289	            });
290	        // Resolver for _freq: this gets executed when the user directly
291	        // modifies _freq.
292	        add_property_resolver(
293	            {freq}, {freq}, [this, chan, &samp_rate_in = *samp_rate_in, &freq = *freq]() {
294	                RFNOC_LOG_TRACE("Calling resolver for `freq'@" << chan);
295	                if (samp_rate_in.is_valid()) {
296	                    const double new_freq =
297	                        _set_freq(freq.get(), samp_rate_in.get(), chan);
298	                    // If the frequency we just set is sufficiently close to the old
299	                    // frequency, don't bother updating the property in software
300	                    if (!uhd::math::frequencies_are_equal(new_freq, freq.get())) {
301	                        freq = new_freq;
302	                    }
303	                } else {
304	                    RFNOC_LOG_DEBUG("Not setting frequency until sampling rate is set.");
305	                }
306	            });
307	        // Resolver for the input rate:
308	        // If this is called, then most likely, the input sampling rate was set.
309	        // In that case, we try and keep the output sampling rate as it was, and
310	        // modify decim to match the input/output ratio. If we can't exactly hit
311	        // the previous output rate, then we coerce the desired decim to a valid
312	        // decim value, and update the output rate.
313	        // Note: This means that if the user set decim explicitly, then this
314	        // resolver can undo the user's intentions. However, it is the option
315	        // that retains the consistency of the graph as much as possible, and
316	        // allows the user to call set_output_rate() on this block before the
317	        // graph was committed.
318	        //
319	        // The scaling is modified in the same resolver to avoid circular
320	        // dependencies. Note that changing the decimation will change the
321	        // scaling ratio (input to output scaling), so we need to write to the
322	        // decimation register in this resolver as well as the decim resolver
323	        // in order to make sure that _residual_scaling is correctly set.
324	        // Otherwise, the decim resolver and this resolver would conflict each
325	        // other when writing to scaling_out.
326	        //
327	        // This resolver may affect the frequency: If the input sampling rate
328	        // was changed, then the phase accumulator increment needs to be
329	        // recalculated in order to retain the current value of the frequency
330	        // offset, which is given in Hz (not in radians).
331	        add_property_resolver({samp_rate_in, scaling_in},
332	            {decim, samp_rate_out, freq, scaling_out},
333	            [this,
334	                chan,
335	                &decim         = *decim,
336	                &freq          = *freq,
337	                &samp_rate_out = *samp_rate_out,
338	                &samp_rate_in  = *samp_rate_in,
339	                &scaling_in    = *scaling_in,
340	                &scaling_out   = *scaling_out]() {
341	                RFNOC_LOG_TRACE(
342	                    "Calling resolver for `samp_rate_in/scaling_in'@" << chan);
343	                if (samp_rate_in.is_valid()) {
344	                    RFNOC_LOG_TRACE("New samp_rate_in is " << samp_rate_in.get());
345	                    if (samp_rate_out.is_valid()) {
346	                        decim = coerce_decim(samp_rate_in.get() / samp_rate_out.get());
347	                        set_decim(decim.get(), chan);
348	                        const double new_samp_rate_out = samp_rate_in.get() / decim.get();
349	                        // Only update the samp_rate_out if the new value is not the same
350	                        // frequency. However, we still want to call the operator= to make
351	                        // sure metadata gets handled
352	                        samp_rate_out = (uhd::math::frequencies_are_equal(
353	                                            samp_rate_out, new_samp_rate_out))
354	                                            ? samp_rate_out.get()
355	                                            : new_samp_rate_out;
356	                        RFNOC_LOG_TRACE("New samp_rate_out is " << samp_rate_out.get());
357	                    } else if (decim.is_valid()) {
358	                        samp_rate_out = samp_rate_in.get() / decim.get();
359	                    }
360	                    // If the input rate changes, we need to update the DDS, too,
361	                    // since it works on frequencies normalized by the input rate.
362	                    freq.force_dirty();
363	                }
364	                if (scaling_in.is_valid()) {
365	                    scaling_out = scaling_in.get() * _residual_scaling.at(chan);
366	                }
367	            });
368	        // Resolver for the output rate: like the previous one, but flipped.
369	        add_property_resolver({samp_rate_out, scaling_out},
370	            {decim, samp_rate_in, scaling_out},
371	            [this,
372	                chan,
373	                &decim         = *decim,
374	                &samp_rate_out = *samp_rate_out,
375	                &samp_rate_in  = *samp_rate_in,
376	                &scaling_in    = *scaling_in,
377	                &scaling_out   = *scaling_out]() {
378	                RFNOC_LOG_TRACE(
379	                    "Calling resolver for `samp_rate_out/scaling_out'@" << chan);
380	                if (samp_rate_out.is_valid()) {
381	                    if (samp_rate_in.is_valid()) {
382	                        decim = coerce_decim(samp_rate_in.get() / samp_rate_out.get());
383	                        set_decim(decim.get(), chan);
384	                    }
385	                    // If decim is dirty, it will trigger the decim resolver.
386	                    // However, the decim resolver will set the output rate based
387	                    // on the input rate, so we need to force the input rate first.
388	                    if (decim.is_dirty()) {
389	                        const double new_samp_rate_in = samp_rate_out.get() * decim.get();
390	                        // Only update the samp_rate_in if the new value is not the same
391	                        // frequency. However, we still want to call the operator= to make
392	                        // sure metadata gets handled
393	                        if (samp_rate_in.is_valid()) {
394	                            samp_rate_in = (uhd::math::frequencies_are_equal(
395	                                               samp_rate_in, new_samp_rate_in))
396	                                               ? samp_rate_in.get()
397	                                               : new_samp_rate_in;
398	                        } else {
399	                            samp_rate_in = new_samp_rate_in;
400	                        }
401	                        RFNOC_LOG_TRACE("New samp_rate_in is " << samp_rate_in.get());
402	                    }
403	                }
404	                if (scaling_in.is_valid()) {
405	                    scaling_out = scaling_in.get() * _residual_scaling.at(chan);
406	                }
407	            });
408	        // Resolvers for type: These are constants
409	        add_property_resolver(
410	            {type_in}, {type_in}, [&type_in = *type_in]() { type_in.set(IO_TYPE_SC16); });
411	        add_property_resolver({type_out}, {type_out}, [&type_out = *type_out]() {
412	            type_out.set(IO_TYPE_SC16);
413	        });
414	    }
415	
416	    void register_issue_stream_cmd()
417	    {
418	        register_action_handler(ACTION_KEY_STREAM_CMD,
419	            [this](const res_source_info& src, action_info::sptr action) {
420	                stream_cmd_action_info::sptr stream_cmd_action =
421	                    std::dynamic_pointer_cast<stream_cmd_action_info>(action);
422	                if (!stream_cmd_action) {
423	                    throw uhd::runtime_error(
424	                        "Received stream_cmd of invalid action type!");
425	                }
426	                issue_stream_cmd_action_handler(src, stream_cmd_action);
427	            });
428	    }
429	
430	    void issue_stream_cmd_action_handler(
431	        const res_source_info& src, stream_cmd_action_info::sptr stream_cmd_action)
432	    {
433	        res_source_info dst_edge{res_source_info::invert_edge(src.type), src.instance};
434	        const size_t chan = src.instance;
435	        uhd::stream_cmd_t::stream_mode_t stream_mode =
436	            stream_cmd_action->stream_cmd.stream_mode;
437	        RFNOC_LOG_TRACE("Received stream command: " << char(stream_mode) << " to "
438	                                                    << src.to_string()
439	                                                    << ", id==" << stream_cmd_action->id);
440	        auto new_action        = stream_cmd_action_info::make(stream_mode);
441	        new_action->stream_cmd = stream_cmd_action->stream_cmd;
442	        if (stream_mode == uhd::stream_cmd_t::STREAM_MODE_NUM_SAMPS_AND_DONE
443	            || stream_mode == uhd::stream_cmd_t::STREAM_MODE_NUM_SAMPS_AND_MORE) {
444	            if (src.type == res_source_info::OUTPUT_EDGE) {
445	                new_action->stream_cmd.num_samps *= _decim.at(chan).get();
446	            } else {
447	                new_action->stream_cmd.num_samps /= _decim.at(chan).get();
448	            }
449	            RFNOC_LOG_TRACE("Forwarding num_samps stream command, new value is "
450	                            << new_action->stream_cmd.num_samps);
451	        }
452	
453	        post_action(dst_edge, new_action, action_mode_t::ASYNC);
454	    }
455	
456	    void register_issue_tune_request()
457	    {
458	        register_action_handler(ACTION_KEY_TUNE_REQUEST,
459	            [this](const res_source_info& src, action_info::sptr action) {
460	                tune_request_action_info::sptr tune_request_action =
461	                    std::dynamic_pointer_cast<tune_request_action_info>(action);
462	                if (!tune_request_action) {
463	                    throw uhd::runtime_error(
464	                        "Received tune_request of invalid action type!");
465	                }
466	                issue_tune_request_action_handler(src, tune_request_action);
467	            });
468	    }
469	
470	    void issue_tune_request_action_handler(
471	        const res_source_info& src, tune_request_action_info::sptr tune_request_action)
472	    {
473	        RFNOC_LOG_TRACE("DDC issue_tune_request_action_handler");
474	        res_source_info dst_edge{res_source_info::invert_edge(src.type), src.instance};
475	        const size_t chan                = src.instance;
476	        uhd::tune_request_t tune_request = tune_request_action->tune_request;
477	        RFNOC_LOG_TRACE("Received tune_request to "
478	                        << src.to_string() << ", id==" << tune_request_action->id);
479	
480	        uhd::freq_range_t dsp_range    = get_frequency_range(chan);
481	        uhd::freq_range_t tune_range   = tune_request_action->overall_freq_range;
482	        tune_request_action->dsp_range = dsp_range;
483	
484	        if (tune_range.empty()) {
485	            tune_range = dsp_range;
486	        }
487	
488	        if (src.type == res_source_info::INPUT_EDGE) {
489	            auto set_dsp_freq = [this, chan](
490	                                    double freq) { set_freq(freq, chan, boost::none); };
491	
492	            double clipped_requested_freq = tune_range.clip(tune_request.target_freq);
493	            tune_request_action->tune_result.target_dsp_freq = std::abs(
494	                tune_request_action->tune_result.actual_rf_freq - clipped_requested_freq);
495	
496	            //------------------------------------------------------------------
497	            //-- Set the DSP frequency depending upon the DSP frequency policy.
498	            //------------------------------------------------------------------
499	            double target_dsp_freq = 0.0;
500	            switch (tune_request.dsp_freq_policy) {
501	                case uhd::tune_request_t::POLICY_AUTO:
502	                    /* If we are using the AUTO tuning policy, then we prevent the
503	                     * CORDIC from spinning us outside of the range of the baseband
504	                     * filter, regardless of what the user requested. This could happen
505	                     * if the user requested a center frequency so far outside of the
506	                     * tunable range of the FE that the CORDIC would spin outside the
507	                     * filtered baseband. */
508	                    target_dsp_freq = tune_request_action->tune_result.target_dsp_freq
509	                                      - tune_request_action->tune_result.actual_dsp_freq;
510	                    break;
511	
512	                case uhd::tune_request_t::POLICY_MANUAL:
513	                    /* If the user has specified a manual tune policy, we will allow
514	                     * tuning outside of the baseband filter, but will still clip the
515	                     * target DSP frequency to within the bounds of the CORDIC to
516	                     * prevent undefined behavior (likely an overflow). */
517	                    target_dsp_freq = dsp_range.clip(tune_request.dsp_freq);
518	                    break;
519	
520	                case uhd::tune_request_t::POLICY_NONE:
521	                    break; // does not set
522	            }
523	            RFNOC_LOG_TRACE(
524	                str(boost::format("Target DSP Freq: %.6fMHz") % (target_dsp_freq / 1e6)));
525	
526	            //------------------------------------------------------------------
527	            //-- Tune the DSP
528	            //------------------------------------------------------------------
529	            if (tune_request.dsp_freq_policy != uhd::tune_request_t::POLICY_NONE) {
530	                set_dsp_freq(target_dsp_freq);
531	            }
532	            const double actual_dsp_freq = get_freq(chan);
533	
534	            RFNOC_LOG_TRACE(
535	                str(boost::format("Actual DSP Freq: %.6fMHz") % (actual_dsp_freq / 1e6)));
536	
537	            tune_request_action->tune_result.actual_dsp_freq += actual_dsp_freq;
538	
539	            RFNOC_LOG_TRACE(
540	                "Tune_result details DDC : target_rf_frq = "
541	                << tune_request_action->tune_result.target_rf_freq
542	                << " target dsp freq = "
543	                << tune_request_action->tune_result.target_dsp_freq << " clipped rf_freq "
544	                << tune_request_action->tune_result.clipped_rf_freq
545	                << " actual_rf_freq = " << tune_request_action->tune_result.actual_rf_freq
546	                << " actual dsp_freq= "
547	                << tune_request_action->tune_result.actual_dsp_freq);
548	
549	            auto new_action                = tune_request_action_info::make(tune_request);
550	            new_action->tune_request       = tune_request_action->tune_request;
551	            new_action->tune_result        = tune_request_action->tune_result;
552	            new_action->dsp_range          = tune_request_action->dsp_range;
553	            new_action->overall_freq_range = tune_request_action->overall_freq_range;
554	            post_action(dst_edge, new_action, action_mode_t::ASYNC);
555	        } else {
556	            auto new_action                = tune_request_action_info::make(tune_request);
557	            new_action->tune_request       = tune_request_action->tune_request;
558	            new_action->tune_result        = tune_request_action->tune_result;
559	            new_action->dsp_range          = tune_request_action->dsp_range;
560	            new_action->overall_freq_range = tune_request_action->overall_freq_range;
561	            post_action(dst_edge, new_action, action_mode_t::ASYNC);
562	        }
563	    }
564	
565	    /**************************************************************************
566	     * FPGA communication (register IO)
567	     *************************************************************************/
568	    /*! Update the decimation value
569	     *
570	     * \param decim The new decimation value. It must be valid decimation value.
571	     * \throws uhd::assertion_error if decim is not valid.
572	     */
573	    void set_decim(int decim, const size_t chan)
574	    {
575	        RFNOC_LOG_TRACE("Set decim to " << decim);
576	        // Step 1: Calculate number of halfbands
577	        uint32_t hb_enable = 0;
578	        uint32_t cic_decim = decim;
579	        while ((cic_decim % 2 == 0) and hb_enable < _num_halfbands) {
580	            hb_enable++;
581	            cic_decim /= 2;
582	        }
583	        // Step 2: Make sure we can handle the rest with the CIC
584	        UHD_ASSERT_THROW(hb_enable <= _num_halfbands);
585	        UHD_ASSERT_THROW(cic_decim > 0 and cic_decim <= _cic_max_decim);
586	        const uint32_t decim_word = (hb_enable << 8) | cic_decim;
587	        _ddc_reg_iface.poke32(SR_DECIM_ADDR, decim_word, chan);
588	
589	        // Rate change = M/N
590	        _ddc_reg_iface.poke32(SR_N_ADDR, decim, chan);
591	        _ddc_reg_iface.poke32(SR_M_ADDR, 1, chan);
592	
593	        // Configure time increment in ticks per M output samples
594	        _ddc_reg_iface.poke32(
595	            SR_TIME_INCR_ADDR, uint32_t(get_tick_rate() / get_output_rate(chan)), chan);
596	
597	        if (cic_decim > 1 and hb_enable == 0) {
598	            RFNOC_LOG_WARNING(
599	                "The requested decimation is odd; the user should expect passband "
600	                "CIC rolloff.\n"
601	                "Select an even decimation to ensure that a halfband filter is "
602	                "enabled.\n"
603	                "Decimations factorable by 4 will enable 2 halfbands, those "
604	                "factorable by 8 will enable 3 halfbands.\n"
605	                "decimation = dsp_rate/samp_rate -> "
606	                << decim);
607	        }
608	
609	        constexpr double DDS_GAIN = 2.0;
610	        // Calculate algorithmic gain of CIC for a given decimation.
611	        // For Ettus CIC R=decim, M=1, N=4. Gain = (R * M) ^ N
612	        // The Ettus CIC also tries its best to compensate for the gain by
613	        // shifting the CIC output. This reduces the gain by a factor of
614	        // 2**ceil(log2(cic_gain))
615	        const double cic_gain = std::pow(double(cic_decim * 1), 4);
616	        // DDS gain:
617	        const double total_gain =
618	            DDS_GAIN * cic_gain / std::pow(2, uhd::math::ceil_log2(cic_gain));
619	        update_scaling(total_gain, chan);
620	    }
621	
622	    //! Update scaling based on the current gain
623	    //
624	    // Calculates the closest fixpoint value that this block can correct for in
625	    // hardware (fixpoint). The residual gain is written to _residual_scaling.
626	    void update_scaling(const double dsp_gain, const size_t chan)
627	    {
628	        constexpr double FIXPOINT_SCALING = 1 << 15;
629	        const double compensation_factor  = 1. / dsp_gain;
630	        // Convert to fixpoint
631	        const double target_factor  = FIXPOINT_SCALING * compensation_factor;
632	        const int32_t actual_factor = std::lround(target_factor);
633	        // Write DDC with scaling correction for CIC and DDS that maximizes
634	        // dynamic range
635	        _ddc_reg_iface.poke32(SR_SCALE_IQ_ADDR, actual_factor, chan);
636	
637	        // Calculate the error introduced by using fixedpoint representation for
638	        // the scaler, can be corrected in host later.
639	        _residual_scaling[chan] = dsp_gain * double(actual_factor) / FIXPOINT_SCALING;
640	    }
641	
642	    /*! Return the closest possible decimation value to the one requested
643	     */
644	    int coerce_decim(const double requested_decim) const
645	    {
646	        UHD_ASSERT_THROW(requested_decim >= 0);
647	        return static_cast<int>(_valid_decims.clip(requested_decim, true));
648	    }
649	
650	    //! Set the DDS frequency shift the signal to \p requested_freq
651	    double _set_freq(
652	        const double requested_freq, const double dds_rate, const size_t chan)
653	    {
654	        double actual_freq;
655	        int32_t freq_word;
656	        std::tie(actual_freq, freq_word) =
657	            get_freq_and_freq_word(requested_freq, dds_rate);
658	
659	        _ddc_reg_iface.poke32(
660	            SR_FREQ_ADDR, uint32_t(freq_word), chan, get_command_time(chan));
661	        return actual_freq;
662	    }
663	
664	    /**************************************************************************
665	     * Attributes
666	     *************************************************************************/
667	    //! Block compat number
668	    const uint32_t _fpga_compat;
669	    //! Number of halfbands
670	    const size_t _num_halfbands;
671	    //! Max CIC decim
672	    const size_t _cic_max_decim;
673	
674	    //! List of valid decimation values
675	    uhd::meta_range_t _valid_decims;
676	
677	    //! Cache the current residual scaling
678	    std::vector<double> _residual_scaling;
679	
680	    //! Properties for type_in (one per port)
681	    std::vector<property_t<std::string>> _type_in;
682	    //! Properties for type_out (one per port)
683	    std::vector<property_t<std::string>> _type_out;
684	    //! Properties for samp_rate_in (one per port)
685	    std::vector<property_t<double>> _samp_rate_in;
686	    //! Properties for samp_rate_out (one per port)
687	    std::vector<property_t<double>> _samp_rate_out;
688	    //! Properties for scaling_in (one per port)
689	    std::vector<property_t<double>> _scaling_in;
690	    //! Properties for scaling_out (one per port)
691	    std::vector<property_t<double>> _scaling_out;
692	    //! Properties for decim (one per port)
693	    std::vector<property_t<int>> _decim;
694	    //! Properties for freq (one per port)
695	    std::vector<property_t<double>> _freq;
696	};
697	
698	UHD_RFNOC_BLOCK_REGISTER_DIRECT(
699	    ddc_block_control, 0xDDC00000, "DDC", CLOCK_KEY_GRAPH, "bus_clk")
700

