56	    RFNOC_BLOCK_CONSTRUCTOR(duc_block_control)
57	    , _duc_reg_iface(*this, 0, REG_CHAN_OFFSET),
58	        _fpga_compat(regs().peek32(RB_COMPAT_NUM)),
59	        _num_halfbands(regs().peek32(RB_NUM_HB)),
60	        _cic_max_interp(regs().peek32(RB_CIC_MAX_INTERP)),
61	        _residual_scaling(get_num_input_ports(), DEFAULT_SCALING)
