68	            get_unique_id(),
69	            get_unique_id(),
70	            false /* Let it slide if minors mismatch */
71	        );
72	        RFNOC_LOG_DEBUG("Loading DUC with " << _num_halfbands
73	                                            << " halfbands and "
74	                                               "max CIC interpolation "
75	                                            << _cic_max_interp);
76	        // This line is not strictly necessary, as ONE_TO_ONE is the default.
77	        // We set it make it explicit how this block works. Output packets have
78	        // the same size as the input packet.
79	        set_mtu_forwarding_policy(forwarding_policy_t::ONE_TO_ONE);
80	        // Load list of valid interpolation values
81	        std::set<size_t> interps{1}; // 1 is always a valid interpolation
82	        for (size_t hb = 0; hb <= _num_halfbands; hb++) {
83	            for (size_t cic_interp = 1; cic_interp <= _cic_max_interp; cic_interp++) {
84	                interps.insert((1 << hb) * cic_interp);
