88	            _valid_interps.push_back(uhd::range_t(double(interp)));
89	        }
90	
91	        // Initialize properties. It is very important to first reserve the
92	        // space, because we use push_back() further down, and properties must
93	        // not change their base address after registration and resolver
94	        // creation.
95	        _samp_rate_in.reserve(get_num_ports());
96	        _samp_rate_out.reserve(get_num_ports());
97	        _scaling_in.reserve(get_num_ports());
98	        _scaling_out.reserve(get_num_ports());
99	        _interp.reserve(get_num_ports());
100	        _freq.reserve(get_num_ports());
101	        _type_in.reserve(get_num_ports());
102	        _type_out.reserve(get_num_ports());
103	        for (size_t chan = 0; chan < get_num_ports(); chan++) {
104	            _register_props(chan);
105	        }
106	        register_issue_stream_cmd();
107	        register_issue_tune_request();
108	    }
109	
110	    double set_freq(const double freq,
111	        const size_t chan,
112	        const boost::optional<uhd::time_spec_t> time) override
113	    {
114	        // Store the current command time so we can restore it later
115	        auto prev_cmd_time = get_command_time(chan);
116	        if (time) {
117	            set_command_time(time.get(), chan);
118	        }
119	        // This will trigger property propagation:
120	        set_property<double>("freq", freq, chan);
121	        set_command_time(prev_cmd_time, chan);
122	        return get_freq(chan);
123	    }
124	
125	    double get_freq(const size_t chan) const override
126	    {
127	        return _freq.at(chan).get();
128	    }
129	
130	    uhd::freq_range_t get_frequency_range(const size_t chan) const override
131	    {
132	        const double output_rate = get_output_rate(chan);
133	        // TODO add steps
134	        return uhd::freq_range_t(-output_rate / 2, output_rate / 2);
135	    }
136	
137	    double get_input_rate(const size_t chan) const override
138	    {
139	        return _samp_rate_in.at(chan).is_valid() ? _samp_rate_in.at(chan).get() : 1.0;
140	    }
141	
142	    double get_output_rate(const size_t chan) const override
143	    {
144	        return _samp_rate_out.at(chan).is_valid() ? _samp_rate_out.at(chan).get() : 1.0;
145	    }
146	
147	    void set_output_rate(const double rate, const size_t chan) override
148	    {
149	        set_property<double>("samp_rate", rate, {res_source_info::OUTPUT_EDGE, chan});
150	    }
151	
152	    uhd::meta_range_t get_input_rates(const size_t chan) const override
153	    {
154	        uhd::meta_range_t result;
155	        if (!_samp_rate_out.at(chan).is_valid()) {
156	            result.push_back(uhd::range_t(1.0));
157	            return result;
158	        }
159	        const double output_rate = _samp_rate_out.at(chan).get();
160	        // The interpolations are stored in order (from smallest to biggest), so
161	        // iterate in reverse order so we can add rates from smallest to biggest
162	        for (auto it = _valid_interps.rbegin(); it != _valid_interps.rend(); ++it) {
163	            result.push_back(uhd::range_t(output_rate / it->start()));
164	        }
165	        return result;
166	    }
167	
168	    double set_input_rate(const double rate, const size_t chan) override
169	    {
170	        if (_samp_rate_out.at(chan).is_valid()) {
171	            const int coerced_interp = coerce_interp(get_output_rate(chan) / rate);
172	            set_property<int>("interp", coerced_interp, chan);
173	        } else {
174	            RFNOC_LOG_DEBUG(
175	                "Property samp_rate@"
176	                << chan
177	                << " is not valid, attempting to set input rate via the edge property.");
178	            set_property<double>("samp_rate", rate, {res_source_info::INPUT_EDGE, chan});
179	        }
180	        return _samp_rate_in.at(chan).get();
181	    }
