194	    /**************************************************************************
195	     * Initialization
196	     *************************************************************************/
197	    void _register_props(const size_t chan)
198	    {
199	        // Create actual properties and store them
200	        _samp_rate_in.push_back(
201	            property_t<double>(PROP_KEY_SAMP_RATE, {res_source_info::INPUT_EDGE, chan}));
202	        _samp_rate_out.push_back(
203	            property_t<double>(PROP_KEY_SAMP_RATE, {res_source_info::OUTPUT_EDGE, chan}));
204	        _scaling_in.push_back(
205	            property_t<double>(PROP_KEY_SCALING, {res_source_info::INPUT_EDGE, chan}));
206	        _scaling_out.push_back(
207	            property_t<double>(PROP_KEY_SCALING, {res_source_info::OUTPUT_EDGE, chan}));
208	        _interp.push_back(property_t<int>(
209	            PROP_KEY_INTERP, DEFAULT_INTERP, {res_source_info::USER, chan}));
210	        _freq.push_back(property_t<double>(
211	            PROP_KEY_FREQ, DEFAULT_FREQ, {res_source_info::USER, chan}));
212	        _type_in.emplace_back(property_t<std::string>(
213	            PROP_KEY_TYPE, IO_TYPE_SC16, {res_source_info::INPUT_EDGE, chan}));
214	        _type_out.emplace_back(property_t<std::string>(
215	            PROP_KEY_TYPE, IO_TYPE_SC16, {res_source_info::OUTPUT_EDGE, chan}));
216	        UHD_ASSERT_THROW(_samp_rate_in.size() == chan + 1);
217	        UHD_ASSERT_THROW(_samp_rate_out.size() == chan + 1);
218	        UHD_ASSERT_THROW(_scaling_in.size() == chan + 1);
219	        UHD_ASSERT_THROW(_scaling_out.size() == chan + 1);
220	        UHD_ASSERT_THROW(_interp.size() == chan + 1);
221	        UHD_ASSERT_THROW(_freq.size() == chan + 1);
222	        UHD_ASSERT_THROW(_type_in.size() == chan + 1);
223	        UHD_ASSERT_THROW(_type_out.size() == chan + 1);
224	
225	        // give us some shorthands for the rest of this function
226	        property_t<double>* samp_rate_in  = &_samp_rate_in.back();
227	        property_t<double>* samp_rate_out = &_samp_rate_out.back();
228	        property_t<double>* scaling_in    = &_scaling_in.back();
229	        property_t<double>* scaling_out   = &_scaling_out.back();
230	        property_t<int>* interp           = &_interp.back();
231	        property_t<double>* freq          = &_freq.back();
232	        property_t<std::string>* type_in  = &_type_in.back();
233	        property_t<std::string>* type_out = &_type_out.back();
234	
235	        // register them
236	        register_property(samp_rate_in);
237	        register_property(samp_rate_out);
238	        register_property(scaling_in);
239	        register_property(scaling_out);
240	        register_property(interp);
241	        register_property(freq);
242	        register_property(type_in);
243	        register_property(type_out);
244	
245	        /**********************************************************************
246	         * Add resolvers
247	         *********************************************************************/
248	        // Resolver for _interp: this gets executed when the user directly
249	        // modifies 'interp'. The desired behaviour is to coerce it first, then
250	        // keep the output rate constant, and re-calculate the input rate.
251	        add_property_resolver({interp, scaling_in},
252	            {interp, samp_rate_out, samp_rate_in, scaling_in},
253	            [this,
254	                chan,
255	                &interp        = *interp,
256	                &samp_rate_out = *samp_rate_out,
257	                &samp_rate_in  = *samp_rate_in,
258	                &scaling_in    = *scaling_in,
259	                &scaling_out   = *scaling_out]() {
260	                RFNOC_LOG_TRACE("Calling resolver for `interp'@" << chan);
261	                interp = coerce_interp(double(interp.get()));
262	                // The following function will also update _residual_scaling
263	                if (interp.is_dirty()) {
264	                    set_interp(interp.get(), chan);
265	                }
266	                if (samp_rate_out.is_valid()) {
267	                    const double new_samp_rate_in = samp_rate_out.get() / interp.get();
268	                    if (samp_rate_in.is_valid()) {
269	                        // Only update the samp_rate_in if the new value is not the same
270	                        // frequency. However, we still want to call the operator= to make
271	                        // sure metadata gets handled
272	                        samp_rate_in = uhd::math::frequencies_are_equal(
273	                                           new_samp_rate_in, samp_rate_in.get())
274	                                           ? samp_rate_in.get()
275	                                           : new_samp_rate_in;
276	                    } else {
277	                        samp_rate_in = new_samp_rate_in;
278	                    }
279	                } else if (samp_rate_in.is_valid()) {
280	                    const double new_samp_rate_out = samp_rate_in.get() * interp.get();
281	                    if (samp_rate_out.is_valid()) {
282	                        // Only update if the new value is not the same frequency
283	                        samp_rate_out = uhd::math::frequencies_are_equal(
284	                                            new_samp_rate_out, samp_rate_out.get())
285	                                            ? samp_rate_out.get()
286	                                            : new_samp_rate_out;
287	                    } else {
288	                        samp_rate_out = new_samp_rate_out;
289	                    }
290	                }
291	                // The scaling is independent of the actual rates
292	                if (scaling_out.is_valid()) {
293	                    scaling_in = scaling_out.get() * _residual_scaling.at(chan);
294	                }
295	            });
296	        // Resolver for _freq: this gets executed when the user directly
297	        // modifies _freq.
298	        add_property_resolver({freq},
299	            {freq},
300	            [this, chan, &samp_rate_out = *samp_rate_out, &freq = *freq]() {
301	                RFNOC_LOG_TRACE("Calling resolver for `freq'@" << chan);
302	                if (samp_rate_out.is_valid()) {
303	                    const double new_freq =
304	                        _set_freq(freq.get(), samp_rate_out.get(), chan);
305	                    // If the frequency we just set is sufficiently close to the old
306	                    // frequency, don't bother updating the property in software
307	                    if (!uhd::math::frequencies_are_equal(new_freq, freq.get())) {
308	                        freq = new_freq;
309	                    }
310	                } else {
311	                    RFNOC_LOG_DEBUG("Not setting frequency until sampling rate is set.");
312	                }
313	            });
314	        // Resolver for the input rate: we try and match interp so that the
315	        // output rate is not modified. if interp needs to be coerced, only then
316	        // the output rate is modified.
317	        // Note this might also affect the frequency (if the output rate is
318	        // modified).
319	        add_property_resolver({samp_rate_in},
320	            {interp, samp_rate_out},
321	            [this,
322	                chan,
323	                &interp        = *interp,
324	                &samp_rate_out = *samp_rate_out,
325	                &samp_rate_in  = *samp_rate_in]() {
326	                const auto UHD_UNUSED(log_chan) = chan;
327	                RFNOC_LOG_TRACE("Calling resolver for `samp_rate_in'@" << chan);
328	                if (samp_rate_in.is_valid()) {
329	                    RFNOC_LOG_TRACE("New samp_rate_in is " << samp_rate_in.get());
330	                    // If interp is changed, that will take care of scaling
331	                    if (samp_rate_out.is_valid()) {
332	                        interp = coerce_interp(samp_rate_out.get() / samp_rate_in.get());
333	                    }
334	                    const double new_samp_rate_out = samp_rate_in.get() * interp.get();
335	                    if (samp_rate_out.is_valid()) {
336	                        // Only update if the new value is not the same frequency
337	                        samp_rate_out = uhd::math::frequencies_are_equal(
338	                                            new_samp_rate_out, samp_rate_out.get())
339	                                            ? samp_rate_out.get()
340	                                            : new_samp_rate_out;
341	                    } else {
342	                        samp_rate_out = new_samp_rate_out;
343	                    }
344	                    RFNOC_LOG_TRACE("New samp_rate_out is " << samp_rate_out.get());
345	                }
346	            });
347	        // Resolver for the output rate: like the previous one, but flipped.
348	        add_property_resolver({samp_rate_out},
349	            {interp, samp_rate_in, freq},
350	            [this,
351	                chan,
352	                &interp        = *interp,
353	                &freq          = *freq,
354	                &samp_rate_out = *samp_rate_out,
355	                &samp_rate_in  = *samp_rate_in]() {
356	                const auto UHD_UNUSED(log_chan) = chan;
357	                RFNOC_LOG_TRACE("Calling resolver for `samp_rate_out'@" << chan);
358	                if (samp_rate_out.is_valid()) {
359	                    // If interp is changed, that will take care of scaling
360	                    if (samp_rate_in.is_valid()) {
361	                        interp =
362	                            coerce_interp(int(samp_rate_out.get() / samp_rate_in.get()));
363	                    }
364	                    const double new_samp_rate_in = samp_rate_out.get() / interp.get();
365	                    if (samp_rate_in.is_valid()) {
366	                        // Only update if the new value is not the same frequency
367	                        samp_rate_in = uhd::math::frequencies_are_equal(
368	                                           new_samp_rate_in, samp_rate_in.get())
369	                                           ? samp_rate_in.get()
370	                                           : new_samp_rate_in;
371	                    } else {
372	                        samp_rate_in = new_samp_rate_in;
373	                    }
374	                    // We now need to force the resolver for freq to run so it can
375	                    // update its phase increment
376	                    freq.force_dirty();
377	                }
378	            });
379	        // Resolver for the output rate: like the previous one, but flipped.
380	        add_property_resolver({scaling_out},
381	            {scaling_in},
382	            [this,
383	                chan,
384	                &interp        = *interp,
385	                &samp_rate_out = *samp_rate_out,
386	                &samp_rate_in  = *samp_rate_in,
387	                &scaling_in    = *scaling_in,
388	                &scaling_out   = *scaling_out]() {
389	                RFNOC_LOG_TRACE("Calling resolver for `scaling_out'@" << chan);
390	                // If any of these are dirty, the interp resolver will kick in
391	                // and calculate the scaling itself, so we don't do it here to
392	                // avoid conflict.
393	                if (!interp.is_dirty() && !samp_rate_in.is_dirty()
394	                    && !samp_rate_out.is_dirty() && scaling_out.is_valid()) {
395	                    scaling_in = scaling_out.get() * _residual_scaling.at(chan);
396	                }
397	            });
398	        // Resolvers for type: These are constants
399	        add_property_resolver(
400	            {type_in}, {type_in}, [&type_in = *type_in]() { type_in.set(IO_TYPE_SC16); });
401	        add_property_resolver({type_out}, {type_out}, [&type_out = *type_out]() {
402	            type_out.set(IO_TYPE_SC16);
403	        });
404	    }
