420	    void issue_stream_cmd_action_handler(
421	        const res_source_info& src, stream_cmd_action_info::sptr stream_cmd_action)
422	    {
423	        res_source_info dst_edge{res_source_info::invert_edge(src.type), src.instance};
424	        const size_t chan = src.instance;
425	        uhd::stream_cmd_t::stream_mode_t stream_mode =
426	            stream_cmd_action->stream_cmd.stream_mode;
427	        RFNOC_LOG_TRACE("Received stream command: " << char(stream_mode) << " to "
428	                                                    << src.to_string()
429	                                                    << ", id==" << stream_cmd_action->id);
430	        auto new_action        = stream_cmd_action_info::make(stream_mode);
431	        new_action->stream_cmd = stream_cmd_action->stream_cmd;
432	        if (stream_mode == uhd::stream_cmd_t::STREAM_MODE_NUM_SAMPS_AND_DONE
433	            || stream_mode == uhd::stream_cmd_t::STREAM_MODE_NUM_SAMPS_AND_MORE) {
434	            if (src.type == res_source_info::INPUT_EDGE) {
435	                new_action->stream_cmd.num_samps *= _interp.at(chan).get();
436	            } else {
437	                new_action->stream_cmd.num_samps /= _interp.at(chan).get();
438	            }
439	            RFNOC_LOG_TRACE("Forwarding num_samps stream command, new value is "
440	                            << new_action->stream_cmd.num_samps);
441	        }
442	
443	        post_action(dst_edge, new_action, action_mode_t::ASYNC);
444	    }
