460	
461	    void issue_tune_request_action_handler(
462	        const res_source_info& src, tune_request_action_info::sptr tune_request_action)
463	    {
464	        RFNOC_LOG_TRACE("DUC isssue_tune_request_action_handler");
465	        res_source_info dst_edge{res_source_info::invert_edge(src.type), src.instance};
466	        const size_t chan                = src.instance;
467	        uhd::tune_request_t tune_request = tune_request_action->tune_request;
468	
469	        RFNOC_LOG_TRACE("Received tune_request to "
470	                        << src.to_string() << ", id==" << tune_request_action->id);
471	
472	        uhd::freq_range_t dsp_range    = get_frequency_range(chan);
473	        uhd::freq_range_t tune_range   = tune_request_action->overall_freq_range;
474	        tune_request_action->dsp_range = dsp_range;
475	
476	        if (tune_range.empty()) {
477	            tune_range = dsp_range;
478	        }
479	
480	        if (src.type == res_source_info::OUTPUT_EDGE) {
481	            auto set_dsp_freq = [this, chan](
482	                                    double freq) { set_freq(freq, chan, boost::none); };
483	
484	            double clipped_requested_freq = tune_range.clip(tune_request.target_freq);
485	            tune_request_action->tune_result.target_dsp_freq = std::abs(
486	                tune_request_action->tune_result.actual_rf_freq - clipped_requested_freq);
487	
488	            //------------------------------------------------------------------
489	            //-- Set the DSP frequency depending upon the DSP frequency policy.
490	            //------------------------------------------------------------------
491	            double target_dsp_freq = 0.0;
492	            switch (tune_request.dsp_freq_policy) {
493	                case uhd::tune_request_t::POLICY_AUTO:
494	                    // invert the sign on the dsp freq for transmit (spinning up vs down)
495	                    tune_request_action->tune_result.target_dsp_freq *= TX_SIGN;
496	
497	                    /* If we are using the AUTO tuning policy, then we prevent the
498	                     * CORDIC from spinning us outside of the range of the baseband
499	                     * filter, regardless of what the user requested. This could happen
500	                     * if the user requested a center frequency so far outside of the
501	                     * tunable range of the FE that the CORDIC would spin outside the
502	                     * filtered baseband. */
503	                    target_dsp_freq = tune_request_action->tune_result.target_dsp_freq
504	                                      - tune_request_action->tune_result.actual_dsp_freq;
505	                    break;
506	
507	                case uhd::tune_request_t::POLICY_MANUAL:
508	                    /* If the user has specified a manual tune policy, we will allow
509	                     * tuning outside of the baseband filter, but will still clip the
510	                     * target DSP frequency to within the bounds of the CORDIC to
511	                     * prevent undefined behavior (likely an overflow). */
512	                    target_dsp_freq = dsp_range.clip(tune_request.dsp_freq);
513	                    break;
514	
515	                case uhd::tune_request_t::POLICY_NONE:
516	                    break; // does not set
517	            }
518	            RFNOC_LOG_TRACE(
519	                str(boost::format("Target DSP Freq: %.6fMHz") % (target_dsp_freq / 1e6)));
520	
521	            //------------------------------------------------------------------
522	            //-- Tune the DSP
523	            //------------------------------------------------------------------
524	            if (tune_request.dsp_freq_policy != uhd::tune_request_t::POLICY_NONE) {
525	                set_dsp_freq(target_dsp_freq);
526	            }
527	            const double actual_dsp_freq = get_freq(chan);
528	
529	            RFNOC_LOG_TRACE(
530	                str(boost::format("Actual DSP Freq: %.6fMHz") % (actual_dsp_freq / 1e6)));
531	
532	            tune_request_action->tune_result.target_dsp_freq = target_dsp_freq;
533	            tune_request_action->tune_result.actual_dsp_freq += actual_dsp_freq;
534	
535	            RFNOC_LOG_TRACE(
536	                "Tune_result details DUC : target_rf_frq = "
537	                << tune_request_action->tune_result.target_rf_freq
538	                << " target dsp freq = "
539	                << tune_request_action->tune_result.target_dsp_freq << " clipped rf_freq "
540	                << tune_request_action->tune_result.clipped_rf_freq
541	                << " actual_rf_freq = " << tune_request_action->tune_result.actual_rf_freq
542	                << " actual dsp_freq= "
543	                << tune_request_action->tune_result.actual_dsp_freq);
544	
545	            auto new_action                = tune_request_action_info::make(tune_request);
546	            new_action->tune_request       = tune_request_action->tune_request;
547	            new_action->tune_result        = tune_request_action->tune_result;
548	            new_action->dsp_range          = tune_request_action->dsp_range;
549	            new_action->overall_freq_range = tune_request_action->overall_freq_range;
550	            post_action(dst_edge, new_action, action_mode_t::ASYNC);
551	        } else {
552	            auto new_action                = tune_request_action_info::make(tune_request);
553	            new_action->tune_request       = tune_request_action->tune_request;
554	            new_action->tune_result        = tune_request_action->tune_result;
555	            new_action->dsp_range          = tune_request_action->dsp_range;
556	            new_action->overall_freq_range = tune_request_action->overall_freq_range;
557	            post_action(dst_edge, new_action, action_mode_t::ASYNC);
558	        }
559	    }
