561	    /**************************************************************************
562	     * FPGA communication (register IO)
563	     *************************************************************************/
564	    /*! Update the interpolation value
565	     *
566	     * \param interp The new interpolation value.
567	     * \throws uhd::assertion_error if interp is not valid.
568	     */
569	    void set_interp(int interp, const size_t chan)
570	    {
571	        RFNOC_LOG_TRACE("Set interp to " << interp);
572	        // Step 1: Calculate number of halfbands
573	        uint32_t hb_enable  = 0;
574	        uint32_t cic_interp = interp;
575	        while ((cic_interp % 2 == 0) and hb_enable < _num_halfbands) {
576	            hb_enable++;
577	            cic_interp /= 2;
578	        }
579	        // Step 2: Make sure we can handle the rest with the CIC
580	        UHD_ASSERT_THROW(hb_enable <= _num_halfbands);
581	        UHD_ASSERT_THROW(cic_interp > 0 and cic_interp <= _cic_max_interp);
582	        const uint32_t interp_word = (hb_enable << 8) | cic_interp;
583	        _duc_reg_iface.poke32(SR_INTERP_ADDR, interp_word, chan);
584	
585	        // Rate change = M/N, where N = 1
586	        _duc_reg_iface.poke32(SR_M_ADDR, interp, chan);
587	        _duc_reg_iface.poke32(SR_N_ADDR, 1, chan);
588	
589	        // Configure time increment in ticks per M output samples
590	        _duc_reg_iface.poke32(
591	            SR_TIME_INCR_ADDR, uint32_t(get_tick_rate() / get_output_rate(chan)), chan);
592	
593	        if (cic_interp > 1 and hb_enable == 0) {
594	            RFNOC_LOG_WARNING(
595	                "The requested interpolation is odd; the user should expect passband "
596	                "CIC rolloff.\n"
597	                "Select an even interpolation to ensure that a halfband filter is "
598	                "enabled.\n");
599	        }
600	
601	        // DDS gain:
602	        constexpr double DDS_GAIN = 1.0;
603	        // Calculate algorithmic gain of CIC for a given interpolation.
604	        // For Ettus CIC R=interp, M=1, N=4. Gain = (R * M) ^ (N - 1)
605	        const double cic_gain = std::pow(double(cic_interp * 1), /*N*/ 4 - 1);
606	        // The Ettus CIC also tries its best to compensate for the gain by
607	        // shifting the CIC output. This reduces the gain by a factor of
608	        // 2**ceil(log2(cic_gain))
609	        const double total_gain =
610	            DDS_GAIN * cic_gain / std::pow(2, uhd::math::ceil_log2(cic_gain));
611	        update_scaling(total_gain, chan);
612	    }
613	
614	    //! Update scaling based on the current gain
615	    //
616	    // Calculates the closest fixpoint value that this block can correct for in
617	    // hardware (fixpoint). The residual gain is written to _residual_scaling.
618	    void update_scaling(const double dsp_gain, const size_t chan)
619	    {
620	        constexpr double FIXPOINT_SCALING = 1 << 15;
621	        const double compensation_factor  = 1. / dsp_gain;
622	        // Convert to fixpoint
623	        const double target_factor  = FIXPOINT_SCALING * compensation_factor;
624	        const int32_t actual_factor = static_cast<int32_t>(std::lround(target_factor));
625	        // Write DUC with scaling correction for CIC and DDS that maximizes
626	        // dynamic range
627	        _duc_reg_iface.poke32(SR_SCALE_IQ_ADDR, actual_factor, chan);
628	
629	        // Calculate the error introduced by using fixedpoint representation for
630	        // the scaler, can be corrected in host later.
631	        _residual_scaling[chan] = dsp_gain * double(actual_factor) / FIXPOINT_SCALING;
632	    }
633	
634	    /*! Return the closest possible interpolation value to the one requested
635	     */
636	    int coerce_interp(const double requested_interp) const
637	    {
638	        UHD_ASSERT_THROW(requested_interp >= 0);
639	        return static_cast<int>(_valid_interps.clip(requested_interp, true));
640	    }
641	
642	    //! Set the DDS frequency shift the signal to \p requested_freq
643	    double _set_freq(
644	        const double requested_freq, const double dds_rate, const size_t chan)
645	    {
646	        double actual_freq;
647	        int32_t freq_word;
648	        std::tie(actual_freq, freq_word) =
649	            get_freq_and_freq_word(requested_freq, dds_rate);
650	
651	        _duc_reg_iface.poke32(
652	            SR_FREQ_ADDR, uint32_t(freq_word), chan, get_command_time(chan));
653	        return actual_freq;
654	    }
655	
656	    /**************************************************************************
657	     * Attributes
658	     *************************************************************************/
659	    //! Block compat number
660	    const uint32_t _fpga_compat;
661	    //! Number of halfbands
662	    const size_t _num_halfbands;
663	    //! Max CIC interpolation
664	    const size_t _cic_max_interp;
665	
666	    //! List of valid interpolation values
667	    uhd::meta_range_t _valid_interps;
668	
669	    //! Cache the current residual scaling
670	    std::vector<double> _residual_scaling;
671	
672	    //! Properties for type_in (one per port)
673	    std::vector<property_t<std::string>> _type_in;
674	    //! Properties for type_out (one per port)
675	    std::vector<property_t<std::string>> _type_out;
676	    //! Properties for samp_rate_in (one per port)
677	    std::vector<property_t<double>> _samp_rate_in;
678	    //! Properties for samp_rate_out (one per port)
679	    std::vector<property_t<double>> _samp_rate_out;
680	    //! Properties for scaling_in (one per port)
681	    std::vector<property_t<double>> _scaling_in;
682	    //! Properties for scaling_out (one per port)
683	    std::vector<property_t<double>> _scaling_out;
684	    //! Properties for interp (one per port)
685	    std::vector<property_t<int>> _interp;
686	    //! Properties for freq (one per port)
687	    std::vector<property_t<double>> _freq;
688	};
689	
690	UHD_RFNOC_BLOCK_REGISTER_DIRECT(
691	    duc_block_control, 0xD0C00000, "DUC", CLOCK_KEY_GRAPH, "bus_clk")
692

