270	    /*
271	     * Get default scaling mask for a given denominator (scaling factor is
272	     * 1/denominator). The function distributes the scaling factor evenly across
273	     * the FFT stages.
274	     *
275	     * Examples:
276	     * - denominator = 1 -> no scaling
277	     * - denominator = 2 -> the scaling will be set to 0b000000000001
278	     *   -> scale by 2 in the first FFT stage
279	     * - denominator = 4 -> the scaling will be set to 0b000000001010
280	     *   -> scale by 4 in both the first and the second FFT stage
281	     * - denominator = 32 -> the scaling will be set to 0b000000011010
282	     *   -> scale by 4 in both the first and the second FFT stage
283	     *   and by 2 in the third FFT stage
284	     */
285	    uint32_t _get_default_scaling(const uint32_t denominator)
286	    {
287	        uint32_t denom_log2 = std::ceil(std::log2(denominator));
288	        uint32_t stage;
289	        uint32_t fft_scale = 0;
290	        for (int32_t i = ((denom_log2 + 1) / 2) - 1; i >= 0; i--) {
291	            if (i == int32_t(denom_log2 / 2)) {
292	                stage = 0b01;
293	            } else {
294	                stage = 0b10;
295	            }
296	            fft_scale = (fft_scale << 2) | stage;
297	        }
298	        return fft_scale;
299	    }
300	
301	    void _set_length(uint32_t length)
302	    {
303	        // Check that the FFT length is within bounds and is a power of 2
304	        uint32_t max_length = get_max_length();
305	        uint32_t min_length = std::max(MIN_FFT_SIZE, 2 * _nipc);
306	        if (length < min_length || length > max_length) {
307	            throw uhd::value_error("FFT length must be a power of two and within ["
308	                                   + std::to_string(min_length) + ", "
309	                                   + std::to_string(max_length) + "]");
310	        }
311	        // Find the log2(length) via highest bit set
312	        uint32_t length_log2      = 0;
313	        uint32_t requested_length = length;
314	        while ((length >>= 1) != 0) {
315	            length_log2++;
316	        }
317	        uint32_t coerced_length = (1 << length_log2);
318	        if (requested_length != coerced_length) {
319	            RFNOC_LOG_WARNING("FFT length "
320	                              << requested_length
321	                              << " not an integral power of two; coercing to "
322	                              << coerced_length);
323	            this->_length.set(coerced_length);
324	        }
325	        RFNOC_LOG_DEBUG("Setting FFT length to " << coerced_length);
326	        regs().poke32(
327	            VERSION_DEPENDENT_ADDR(REG_LENGTH_LOG2_ADDR), uint32_t(length_log2));
328	
329	        // Check to make sure register was updated correctly
330	        length_log2 = regs().peek32(VERSION_DEPENDENT_ADDR(REG_LENGTH_LOG2_ADDR));
331	        uint32_t readback_length = (1 << length_log2);
332	        if (readback_length != coerced_length) {
333	            throw uhd::value_error("FFT Size readback failed! "
334	                                   "Expected: "
335	                                   + std::to_string(coerced_length)
336	                                   + ", "
337	                                     "Received: "
338	                                   + std::to_string(readback_length));
339	        }
340	    }
