342	    void _set_magnitude(int mag)
343	    {
344	        if (mag < static_cast<int>(fft_magnitude::COMPLEX)
345	            || mag > static_cast<int>(fft_magnitude::MAGNITUDE_SQUARED)) {
346	            throw uhd::value_error("Magnitude value must be in the range [0, 2]");
347	        } else if ((static_cast<fft_magnitude>(mag) == fft_magnitude::MAGNITUDE)
348	                   and not _magnitude_supported) {
349	            throw uhd::value_error("Magnitude value MAGNITUDE(1) is not supported");
350	        } else if ((static_cast<fft_magnitude>(mag) == fft_magnitude::MAGNITUDE_SQUARED)
351	                   and not _magnitude_squared_supported) {
352	            throw uhd::value_error(
353	                "Magnitude value MAGNITUDE_SQUARED(2) is not supported");
354	        }
355	        regs().poke32(VERSION_DEPENDENT_ADDR(REG_MAGNITUDE_ADDR), uint32_t(mag));
356	        int readback_mag = int(regs().peek32(VERSION_DEPENDENT_ADDR(REG_MAGNITUDE_ADDR)));
357	        if (readback_mag != mag) {
358	            throw uhd::value_error("Magnitude readback failed! "
359	                                   "Expected: "
360	                                   + std::to_string(mag)
361	                                   + ", "
362	                                     "Received: "
363	                                   + std::to_string(readback_mag));
364	        }
365	    }
