367	    void _set_direction(fft_direction direction)
368	    {
369	        if (direction != fft_direction::REVERSE && direction != fft_direction::FORWARD) {
370	            throw uhd::value_error(
371	                "FFT Direction value " + std::to_string(static_cast<uint32_t>(direction))
372	                + " is invalid, must be equal to either "
373	                + std::to_string(static_cast<uint32_t>(fft_direction::FORWARD))
374	                + " (Forward aka FFT) or "
375	                + std::to_string(static_cast<uint32_t>(fft_direction::REVERSE))
376	                + " (Reverse aka IFFT)");
377	        }
378	        RFNOC_LOG_DEBUG("Setting FFT Direction to " << static_cast<uint32_t>(direction));
379	        regs().poke32(
380	            VERSION_DEPENDENT_ADDR(REG_DIRECTION_ADDR), static_cast<uint32_t>(direction));
381	
382	        fft_direction readback_direction = get_direction();
383	        if (readback_direction != direction) {
384	            throw uhd::value_error(
385	                "FFT Direction readback failed! "
386	                "Expected: "
387	                + std::to_string(static_cast<uint32_t>(direction))
388	                + ", "
389	                  "Received: "
390	                + std::to_string(static_cast<uint32_t>(readback_direction)));
391	        }
392	    }
