394	    void _set_scaling(uint32_t scaling)
395	    {
396	        // Check that FFT scale is within bounds
397	        const uint32_t scale_width =
398	            static_cast<uint32_t>(2 * std::ceil(log2(double(_length)) / 2));
399	        const uint32_t max_scale = (1 << scale_width) - 1;
400	        if (scaling > max_scale) {
401	            throw uhd::value_error(str(
402	                boost::format(
403	                    "FFT scaling mask 0x%08x is greater then max. supported mask 0x%08x")
404	                % scaling % max_scale));
405	        }
406	        RFNOC_LOG_DEBUG("Setting FFT Scaling to " << scaling);
407	        regs().poke32(VERSION_DEPENDENT_ADDR(REG_SCALING_ADDR), scaling);
408	
409	        uint32_t readback_scaling =
410	            regs().peek32(VERSION_DEPENDENT_ADDR(REG_SCALING_ADDR));
411	        if (readback_scaling != scaling) {
412	            throw uhd::value_error("FFT Scaling readback failed! "
413	                                   "Expected: "
414	                                   + std::to_string(scaling)
415	                                   + ", "
416	                                     "Received: "
417	                                   + std::to_string(readback_scaling));
418	        }
419	    }
