421	    void _set_shift_config(int shift)
422	    {
423	        if (_fpga_compat.get_major() == 1
424	            && (shift < static_cast<int>(fft_shift::NORMAL)
425	                || shift > static_cast<int>(fft_shift::NATURAL))) {
426	            throw uhd::value_error("Shift value must be in the range [0, 2]");
427	        } else if (shift < static_cast<int>(fft_shift::NORMAL)
428	                   || shift > static_cast<int>(fft_shift::BIT_REVERSE)) {
429	            throw uhd::value_error("Shift value must be in the range [0, 3]");
430	        } else if (not _fft_shift_supported) {
431	            throw uhd::value_error("Shift capability is not present in the FFT block. "
432	                                   "The native FFT output order will be used.");
433	        }
434	        this->regs().poke32(VERSION_DEPENDENT_ADDR(REG_ORDER_ADDR), uint32_t(shift));
435	    }
