467	    void _set_cp_insertion_list(const std::vector<uint32_t> cp_lengths)
468	    {
469	        if (_fpga_compat.get_major() == 1) {
470	            if (cp_lengths.size() > 0) {
471	                throw uhd::value_error("Block does not support CP insertion");
472	            }
473	            return;
474	        }
475	        if (cp_lengths.size() > _max_cp_insertion_list_length) {
476	            throw uhd::value_error(
477	                "Vector size of insertion Cyclic Prefix Lengths is too large. "
478	                "Must be between 1 and "
479	                + std::to_string(_max_cp_insertion_list_length) + ".");
480	        }
481	        for (auto& cp_length : cp_lengths) {
482	            if (cp_length > get_max_cp_length()) {
483	                throw uhd::value_error("CP insertion length " + std::to_string(cp_length)
484	                                       + " is too "
485	                                         "large. Must be between 1 and "
486	                                       + std::to_string(get_max_cp_length()) + ".");
487	            } else if (cp_length % _nipc != 0) {
488	                throw uhd::value_error("CP insertion length " + std::to_string(cp_length)
489	                                       + " is not a multiple of the NIPC value "
490	                                       + std::to_string(_nipc) + ".");
491	            }
492	        }
493	
494	        _clear_cp_insertion_fifo();
495	
496	        // Write cyclic prefix lengths into config FIFO
497	        uint32_t readback_cp_length;
498	        for (auto& cp_length : cp_lengths) {
499	            regs().poke32(REG_CP_INS_LEN_ADDR, cp_length);
500	            regs().poke32(REG_CP_INS_LIST_LOAD_ADDR, 1);
501	            RFNOC_LOG_DEBUG("Setting insertion Cyclic Prefix Length " << cp_length);
502	            readback_cp_length = regs().peek32(REG_CP_INS_LEN_ADDR);
503	            if (readback_cp_length != cp_length) {
504	                throw uhd::value_error("Insertion Cyclic Prefix length readback failed! "
505	                                       "Expected: "
506	                                       + std::to_string(cp_length) + ", " + "Received: "
507	                                       + std::to_string(readback_cp_length));
508	            }
509	        }
510	
511	        uint32_t cp_insertion_fifo_fifo_occupancy =
512	            regs().peek32(REG_CP_INS_LIST_OCC_ADDR);
513	        if (cp_insertion_fifo_fifo_occupancy != cp_lengths.size()) {
514	            throw uhd::value_error(
515	                "Checking Cyclic Prefix Insertion FIFO after writing failed. "
516	                "Expected FIFO occupancy: "
517	                + std::to_string(cp_lengths.size()) + ", Actual FIFO occupancy: "
518	                + std::to_string(cp_insertion_fifo_fifo_occupancy));
519	        }
520	    }
