569	        if (cp_removal_fifo_fifo_occupancy != cp_lengths.size()) {
570	            throw uhd::value_error(
571	                "Checking Cyclic Prefix Removal FIFO after writing failed. "
572	                "Expected FIFO occupancy: "
573	                + std::to_string(cp_lengths.size()) + ", Actual FIFO occupancy: "
574	                + std::to_string(cp_removal_fifo_fifo_occupancy));
575	        }
