578	    void _atomic_item_size_check(size_t port)
579	    {
580	        if (_fpga_compat.get_major() == 1) {
581	            // FFT v1 requires atomic item size to be equal to the
582	            // FFT length (in bytes)
583	            size_t ais = _length.get() * BYTES_PER_SAMPLE;
584	            if (_atomic_item_size_in.at(port) != ais
585	                || _atomic_item_size_out.at(port) != ais) {
586	                RFNOC_LOG_WARNING("Atomic item size for FFT v1 needs to match FFT length "
587	                                  "(in bytes), setting atomic item size to: "
588	                                  << ais);
589	                _atomic_item_size_in.at(port)  = ais;
590	                _atomic_item_size_out.at(port) = ais;
591	            }
592	        } else if (_fpga_compat >= MIN_COMPAT_MULTI_SPC) {
593	            // As of this compat number, the atomic item size must be a
594	            // multiple of the NIPC.
595	            if (_atomic_item_size_in.at(port) % _nipc != 0) {
596	                // Round up to the nearest multiple of NIPC
597	                const size_t bytes_per_clk = _nipc * BYTES_PER_SAMPLE;
598	                const size_t ais_in =
599	                    std::lcm<size_t>(bytes_per_clk, _atomic_item_size_in.at(port).get());
600	                RFNOC_LOG_TRACE("Resolving atomic item size in to " << ais_in);
601	                _atomic_item_size_in.at(port) = ais_in;
602	            }
603	            if (_atomic_item_size_out.at(port) % _nipc != 0) {
604	                // Round up to the nearest multiple of NIPC
605	                const size_t bytes_per_clk = _nipc * BYTES_PER_SAMPLE;
606	                const size_t ais_out =
607	                    std::lcm<size_t>(bytes_per_clk, _atomic_item_size_out.at(port).get());
608	                RFNOC_LOG_TRACE("Resolving atomic item size out to " << ais_out);
609	                _atomic_item_size_out.at(port) = ais_out;
610	            }
611	        } else if ((_cp_insertion_list.get().size() > 0)
612	                   || (_cp_removal_list.get().size() > 0)) {
613	            // If the cyclic prefix insertion list is not empty,
614	            // packets which are generated by the FFT block are of
615	            // different size (FFT length; CP insertion length)
616	            // Hence, the atomic item size needs to be set to the
617	            // greatest common divisor of the possible packet sizes.
618	            // For simplicity, set it to 1 * bytes per sample
619	            size_t ais = 1 * BYTES_PER_SAMPLE;
620	            if (_atomic_item_size_in.at(port) != ais
621	                || _atomic_item_size_out.at(port) != ais) {
622	                RFNOC_LOG_WARNING(
623	                    "Atomic item size cannot be modified because FFT block is configured "
624	                    "with CP insertion or CP removal, setting atomic item size to: "
625	                    << ais);
626	                _atomic_item_size_in.at(port)  = ais;
627	                _atomic_item_size_out.at(port) = ais;
628	            }
629	            _atomic_item_size_in.at(port)  = 1 * BYTES_PER_SAMPLE;
630	            _atomic_item_size_out.at(port) = 1 * BYTES_PER_SAMPLE;
631	        } else if ((_atomic_item_size_in.at(port) > (_length.get() * BYTES_PER_SAMPLE))
632	                   || (_atomic_item_size_out.at(port)
633	                       > (_length.get() * BYTES_PER_SAMPLE))) {
634	            // if the atomic item size is greater than the FFT length
635	            // (in bytes), limit it by the FFT length (in bytes)
636	            size_t ais = _length.get() * BYTES_PER_SAMPLE;
637	            if (_atomic_item_size_in.at(port) != ais
638	                || _atomic_item_size_out.at(port) != ais) {
639	                RFNOC_LOG_WARNING("Requested atomic item size exceeded FFT length (in "
640	                                  "bytes), setting atomic item size to: "
641	                                  << ais);
642	                _atomic_item_size_in.at(port)  = ais;
643	                _atomic_item_size_out.at(port) = ais;
644	            }
645	        }
646	    }
