649	     * Initialization
650	     *************************************************************************/
651	    void _register_props()
652	    {
653	        register_property(&_length);
654	
655	        for (size_t port = 0; port < _num_ports; port++) {
656	            register_property(&_atomic_item_size_in.at(port));
657	            register_property(&_atomic_item_size_out.at(port));
658	
659	            // use add_property_resolver to allow setting coerced length
660	            add_property_resolver({&_length},
661	                {&_length,
662	                    &_atomic_item_size_in.at(port),
663	                    &_atomic_item_size_out.at(port)},
664	                [this, port]() {
665	                    uint32_t length = static_cast<uint32_t>(this->_length.get());
666	                    RFNOC_LOG_TRACE("Calling resolver for `length'");
667	                    _set_length(length);
668	                    _atomic_item_size_check(port);
669	                });
670	        }
671	
672	        register_property(&_magnitude, [this]() {
673	            int mag = this->_magnitude.get();
674	            RFNOC_LOG_TRACE("Calling resolver for `magnitude'");
675	            _set_magnitude(mag);
676	        });
677	
678	        register_property(&_direction, [this]() {
679	            fft_direction direction = static_cast<fft_direction>(_direction.get());
680	            RFNOC_LOG_TRACE("Calling resolver for `direction'");
681	            _set_direction(direction);
682	        });
683	
684	        register_property(&_scaling, [this]() {
685	            uint32_t scaling = static_cast<uint32_t>(_scaling.get());
686	            RFNOC_LOG_TRACE("Calling resolver for `fft_scaling'");
687	            _set_scaling(scaling);
688	        });
689	
690	        register_property(&_scaling_factor);
691	        add_property_resolver(
692	            {&_scaling_factor}, {&_scaling, &_scaling_factor}, [this]() {
693	                double factor           = static_cast<double>(_scaling_factor.get());
694	                uint32_t scaling_length = uint32_t(1.0 / factor);
695	                uint32_t scaling        = _get_default_scaling(scaling_length);
696	                RFNOC_LOG_TRACE("Calling resolver for `fft_scaling_factor'");
697	                _set_scaling(scaling);
698	                this->_scaling.set(scaling);
699	            });
700	
701	        register_property(&_shift, [this]() {
702	            int shift = this->_shift.get();
703	            RFNOC_LOG_TRACE("Calling resolver for `shift_config'");
704	            _set_shift_config(shift);
705	        });
706	
707	        register_property(&_bypass_mode_property, [this]() {
708	            bool bypass = this->_bypass_mode_property.get();
709	            RFNOC_LOG_TRACE("Calling resolver for `bypass_mode'");
710	            _set_bypass_mode(bypass);
711	        });
712	
713	        register_property(&_cp_insertion_list);
714	        register_property(&_cp_removal_list);
715	        for (size_t port = 0; port < _num_ports; port++) {
716	            add_property_resolver({&_cp_insertion_list},
717	                {&_cp_insertion_list,
718	                    &_atomic_item_size_in.at(port),
719	                    &_atomic_item_size_out.at(port)},
720	                [this, port]() {
721	                    std::vector<uint32_t> cp_insertion_list =
722	                        this->_cp_insertion_list.get();
723	                    RFNOC_LOG_TRACE("Calling resolver for `cp_insertion_list'");
724	                    _set_cp_insertion_list(cp_insertion_list);
725	                    _atomic_item_size_check(port);
726	                });
727	
728	            add_property_resolver({&_cp_removal_list},
729	                {&_cp_removal_list,
730	                    &_atomic_item_size_in.at(port),
731	                    &_atomic_item_size_out.at(port)},
732	                [this, port]() {
733	                    std::vector<uint32_t> cp_removal_list = this->_cp_removal_list.get();
734	                    RFNOC_LOG_TRACE("Calling resolver for `cp_removal_list'");
735	                    _set_cp_removal_list(cp_removal_list);
736	                    _atomic_item_size_check(port);
737	                });
738	        }
739	
740	        register_property(&_nipc_property);
741	        add_property_resolver({&_nipc_property}, {&_nipc_property}, [this]() {
742	            RFNOC_LOG_TRACE("Calling resolver for `nipc'");
743	            this->_nipc_property.set(this->_nipc);
744	        });
745	        register_property(&_max_length_property);
746	        add_property_resolver({&_max_length_property}, {&_max_length_property}, [this]() {
747	            RFNOC_LOG_TRACE("Calling resolver for `max_length'");
748	            this->_max_length_property.set(this->_max_length);
749	        });
750	        register_property(&_max_cp_length_property);
751	        add_property_resolver(
752	            {&_max_cp_length_property}, {&_max_cp_length_property}, [this]() {
753	                RFNOC_LOG_TRACE("Calling resolver for `max_cp_length'");
754	                this->_max_cp_length_property.set(this->_max_cp_length);
755	            });
756	        register_property(&_max_cp_insertion_list_length_property);
757	        add_property_resolver({&_max_cp_insertion_list_length_property},
758	            {&_max_cp_insertion_list_length_property},
759	            [this]() {
760	                RFNOC_LOG_TRACE("Calling resolver for `max_cp_insertion_list_length'");
761	                this->_max_cp_insertion_list_length_property.set(
762	                    this->_max_cp_insertion_list_length);
763	            });
764	        register_property(&_max_cp_removal_list_length_property);
765	        add_property_resolver({&_max_cp_removal_list_length_property},
766	            {&_max_cp_removal_list_length_property},
767	            [this]() {
768	                RFNOC_LOG_TRACE("Calling resolver for `max_cp_removal_list_length'");
769	                this->_max_cp_removal_list_length_property.set(
770	                    this->_max_cp_removal_list_length);
771	            });
772	
773	        for (size_t port = 0; port < _num_ports; port++) {
774	            // register edge properties
775	            register_property(&_type_in.at(port));
776	            register_property(&_type_out.at(port));
777	            // add resolvers for type (keeps it constant)
778	            add_property_resolver({&_type_in.at(port)},
779	                {&_type_in.at(port)},
780	                [&type_in = _type_in.at(port)]() { type_in.set(IO_TYPE_SC16); });
781	            add_property_resolver({&_type_out.at(port)},
782	                {&_type_out.at(port)},
783	                [&type_out = _type_out.at(port)]() { type_out.set(IO_TYPE_SC16); });
784	
785	            // Add resolvers for atomic item size
786	            add_property_resolver({&_atomic_item_size_in.at(port)},
787	                {&_atomic_item_size_in.at(port), &_atomic_item_size_out.at(port)},
788	                [this, port]() {
789	                    RFNOC_LOG_TRACE(
790	                        "Calling resolver for `atomic_item_size' (triggered from "
791	                        "input edge)");
792	                    _atomic_item_size_out.at(port) = _atomic_item_size_in.at(port).get();
793	                    _atomic_item_size_check(port);
794	                });
795	            add_property_resolver({&_atomic_item_size_out.at(port)},
796	                {&_atomic_item_size_in.at(port), &_atomic_item_size_out.at(port)},
797	                [this, port]() {
798	                    RFNOC_LOG_TRACE(
799	                        "Calling resolver for `atomic_item_size' (triggered from "
800	                        "output edge)");
801	                    _atomic_item_size_in.at(port) = _atomic_item_size_out.at(port).get();
802	                    _atomic_item_size_check(port);
803	                });
804	        }
805	    }
806	
807	    /**************************************************************************
808	     * Attributes
809	     *************************************************************************/
810	    //! Block compat number
811	    const uhd::compat_num32 _fpga_compat;
812	    //! Block capabilities
813	    const uint32_t _capabilities;
814	    const uint32_t _capabilities2;
815	    const uint32_t _max_length;
816	    const uint32_t _max_cp_length;
817	    const uint32_t _max_cp_removal_list_length;
818	    const uint32_t _max_cp_insertion_list_length;
819	    const uint32_t _nipc;
820	    const bool _magnitude_squared_supported;
821	    const bool _magnitude_supported;
822	    const bool _fft_shift_supported;
823	    const bool _bypass_mode_supported;
824	    const size_t _num_ports;
825	
826	    property_t<int> _length{PROP_KEY_LENGTH, DEFAULT_LENGTH, {res_source_info::USER}};
827	    property_t<int> _magnitude = property_t<int>{
828	        PROP_KEY_MAGNITUDE, static_cast<int>(DEFAULT_MAGNITUDE), {res_source_info::USER}};
829	    property_t<int> _direction = property_t<int>{
830	        PROP_KEY_DIRECTION, static_cast<int>(DEFAULT_DIRECTION), {res_source_info::USER}};
831	    property_t<int> _scaling = property_t<int>{
832	        PROP_KEY_FFT_SCALING, DEFAULT_FFT_SCALING, {res_source_info::USER}};
833	    property_t<double> _scaling_factor = property_t<double>{
834	        PROP_KEY_FFT_SCALING_FACTOR, DEFAULT_FFT_SCALING_FACTOR, {res_source_info::USER}};
835	    property_t<int> _shift = property_t<int>{
836	        PROP_KEY_SHIFT_CONFIG, static_cast<int>(DEFAULT_SHIFT), {res_source_info::USER}};
837	    property_t<bool> _bypass_mode_property = property_t<bool>{PROP_KEY_BYPASS_MODE,
838	        static_cast<bool>(DEFAULT_BYPASS_MODE),
839	        {res_source_info::USER}};
840	    property_t<std::vector<uint32_t>> _cp_insertion_list =
841	        property_t<std::vector<uint32_t>>{
842	            PROP_KEY_CP_INSERTION_LIST, std::vector<uint32_t>(), {res_source_info::USER}};
843	    property_t<std::vector<uint32_t>> _cp_removal_list =
844	        property_t<std::vector<uint32_t>>{
845	            PROP_KEY_CP_REMOVAL_LIST, std::vector<uint32_t>(), {res_source_info::USER}};
846	    property_t<uint32_t> _nipc_property =
847	        property_t<uint32_t>{PROP_KEY_NIPC, _nipc, {res_source_info::USER}};
848	    property_t<uint32_t> _max_length_property =
849	        property_t<uint32_t>{PROP_KEY_MAX_LENGTH, _max_length, {res_source_info::USER}};
850	    property_t<uint32_t> _max_cp_length_property = property_t<uint32_t>{
851	        PROP_KEY_MAX_CP_LENGTH, _max_cp_length, {res_source_info::USER}};
852	    property_t<uint32_t> _max_cp_insertion_list_length_property =
853	        property_t<uint32_t>{PROP_KEY_MAX_CP_INSERTION_LIST_LENGTH,
854	            _max_cp_insertion_list_length,
855	            {res_source_info::USER}};
856	    property_t<uint32_t> _max_cp_removal_list_length_property =
857	        property_t<uint32_t>{PROP_KEY_MAX_CP_REMOVAL_LIST_LENGTH,
858	            _max_cp_removal_list_length,
859	            {res_source_info::USER}};
860	
861	    std::vector<property_t<size_t>> _atomic_item_size_in;
862	    std::vector<property_t<size_t>> _atomic_item_size_out;
863	    std::vector<property_t<std::string>> _type_in;
864	    std::vector<property_t<std::string>> _type_out;
865	};
866	
867	
868	static std::vector<noc_id_t> FFT_NOC_IDS{FFT_BLOCK_V1, FFT_BLOCK_V2};
869	UHD_RFNOC_BLOCK_REGISTER_DIRECT(
870	    fft_block_control, FFT_NOC_IDS, "FFT", CLOCK_KEY_GRAPH, "bus_clk")
871

