94	        _num_input_ports(get_num_input_ports()),
95	        _num_output_ports(get_num_output_ports()),
96	        _fpga_compat(_replay_reg_iface.peek32(REG_COMPAT_ADDR)),
97	        _word_size(
98	            uint16_t((_replay_reg_iface.peek32(REG_MEM_SIZE_ADDR) >> 16) & 0xFFFF) / 8),
99	        _mem_size(
100	            uint64_t(1ULL << (_replay_reg_iface.peek32(REG_MEM_SIZE_ADDR) & 0xFFFF))),
101	        _cmd_fifo_spaces(_num_output_ports)
102	    {
103	        if (get_num_input_ports() != get_num_output_ports()) {
104	            throw uhd::assertion_error(
105	                "Replay block has invalid hardware configuration! Number of input ports "
106	                "does not match number of output ports.");
107	        }
108	        uhd::assert_fpga_compat(MAJOR_COMPAT,
109	            MINOR_COMPAT,
110	            _fpga_compat,
111	            get_unique_id(),
112	            get_unique_id(),
113	            false /* Let it slide if minors mismatch */
114	        );
115	        RFNOC_LOG_TRACE(
116	            "Initializing replay block with num ports=" << get_num_input_ports());
117	        // Properties and actions can't propagate through this block, as we
118	        // treat source and sink of this block like the radio (they terminate
119	        // the graph).
120	        set_prop_forwarding_policy(forwarding_policy_t::DROP);
121	        set_action_forwarding_policy(forwarding_policy_t::DROP);
122	        // Same for MTU
123	        set_mtu_forwarding_policy(forwarding_policy_t::DROP);
124	        // Register action handler
125	        register_action_handler(ACTION_KEY_STREAM_CMD,
126	            [this](const res_source_info& src, action_info::sptr action) {
127	                stream_cmd_action_info::sptr stream_cmd_action =
128	                    std::dynamic_pointer_cast<stream_cmd_action_info>(action);
129	                if (!stream_cmd_action) {
130	                    RFNOC_LOG_WARNING("Received invalid stream command action!");
131	                    return;
132	                }
133	                RFNOC_LOG_TRACE("Received stream command: "
134	                                << stream_cmd_action->stream_cmd.stream_mode << " to "
135	                                << src.to_string());
136	                if (src.type != res_source_info::OUTPUT_EDGE) {
137	                    RFNOC_LOG_WARNING(
138	                        "Received stream command, but not to output port! Ignoring.");
139	                    return;
140	                }
141	                const size_t port = src.instance;
142	                if (port >= get_num_output_ports()) {
143	                    RFNOC_LOG_WARNING("Received stream command to invalid output port!");
144	                    return;
145	                }
146	                issue_stream_cmd(stream_cmd_action->stream_cmd, port);
147	            });
148	        register_action_handler(ACTION_KEY_RX_EVENT,
149	            [this](const res_source_info& src, action_info::sptr action) {
150	                rx_event_action_info::sptr rx_event_action =
151	                    std::dynamic_pointer_cast<rx_event_action_info>(action);
152	                if (!rx_event_action) {
153	                    RFNOC_LOG_WARNING("Received invalid RX event action!");
154	                    return;
155	                }
156	                _handle_rx_event_action(src, rx_event_action);
157	            });
158	        register_action_handler(ACTION_KEY_TX_EVENT,
159	            [this](const res_source_info& src, action_info::sptr action) {
160	                tx_event_action_info::sptr tx_event_action =
161	                    std::dynamic_pointer_cast<tx_event_action_info>(action);
162	                if (!tx_event_action) {
163	                    RFNOC_LOG_WARNING("Received invalid TX event action!");
164	                    return;
165	                }
166	                _handle_tx_event_action(src, tx_event_action);
167	            });
168	        register_action_handler(ACTION_KEY_TUNE_REQUEST,
169	            [this](const res_source_info& src, action_info::sptr action) {
170	                tune_request_action_info::sptr tune_request_action =
171	                    std::dynamic_pointer_cast<tune_request_action_info>(action);
172	                if (!tune_request_action) {
173	                    RFNOC_LOG_WARNING("Received invalid tune request action!");
174	                    return;
175	                }
176	                RFNOC_LOG_DEBUG("Received tune request on " << src.to_string());
177	            });
178	
179	        // Initialize record properties
180	        _record_type.reserve(_num_input_ports);
181	        _record_offset.reserve(_num_input_ports);
182	        _record_size.reserve(_num_input_ports);
183	        _atomic_item_size_in.reserve(_num_input_ports);
184	        for (size_t port = 0; port < _num_input_ports; port++) {
185	            _register_input_props(port);
186	            _replay_reg_iface.poke64(
187	                REG_REC_BASE_ADDR_LO_ADDR, _record_offset.at(port).get(), port);
188	            _replay_reg_iface.poke64(
189	                REG_REC_BUFFER_SIZE_LO_ADDR, _record_size.at(port).get(), port);
190	        }
191	
192	
193	        // Initialize playback properties
194	        _play_type.reserve(_num_output_ports);
195	        _play_offset.reserve(_num_output_ports);
196	        _play_size.reserve(_num_output_ports);
197	        _play_follow_mode.reserve(_num_output_ports);
198	        _payload_size.reserve(_num_output_ports);
199	        _atomic_item_size_out.reserve(_num_output_ports);
200	        for (size_t port = 0; port < _num_output_ports; port++) {
201	            _register_output_props(port);
202	            _replay_reg_iface.poke32(REG_PLAY_ITEM_SIZE_ADDR,
203	                uhd::convert::get_bytes_per_item(_play_type.at(port).get()),
204	                port);
205	            _replay_reg_iface.poke64(
206	                REG_PLAY_BASE_ADDR_LO_ADDR, _play_offset.at(port).get(), port);
207	            _replay_reg_iface.poke64(
208	                REG_PLAY_BUFFER_SIZE_LO_ADDR, _play_size.at(port).get(), port);
209	            _replay_reg_iface.poke32(REG_PLAY_WORDS_PER_PKT_ADDR,
210	                (_payload_size.at(port).get()) / _word_size,
211	                port);
212	            // The register to get the command FIFO space was added in v1.1
213	            if (_fpga_compat >= 0x00010001) {
214	                _cmd_fifo_spaces[port] =
215	                    _replay_reg_iface.peek32(REG_PLAY_CMD_FIFO_SPACE_ADDR, port);
216	            }
217	        }
218	    }
