254	    void play(const uint64_t offset,
255	        const uint64_t size,
256	        const size_t port,
257	        const uhd::time_spec_t time_spec,
258	        const size_t iterations) override
259	    {
260	        config_play(offset, size, port);
261	        uhd::stream_cmd_t play_cmd =
262	            iterations == PLAY_CONTINUOUS
263	                ? uhd::stream_cmd_t(uhd::stream_cmd_t::STREAM_MODE_START_CONTINUOUS)
264	                : uhd::stream_cmd_t(uhd::stream_cmd_t::STREAM_MODE_NUM_SAMPS_AND_DONE);
265	        play_cmd.num_samps  = iterations == PLAY_CONTINUOUS
266	                                  ? 0
267	                                  : iterations * size / get_play_item_size(port);
268	        play_cmd.time_spec  = time_spec;
269	        play_cmd.stream_now = (time_spec == 0.0);
270	        issue_stream_cmd(play_cmd, port);
271	    }
