428	    void issue_stream_cmd(const uhd::stream_cmd_t& stream_cmd, const size_t port) override
429	    {
430	        // Ensure that the buffer is properly configured before issuing a stream command
431	        _validate_play_buffer(port);
432	        RFNOC_LOG_TRACE("replay_block_control_impl::issue_stream_cmd(port="
433	                        << port << ", mode=" << char(stream_cmd.stream_mode) << ")");
434	
435	        // Setup the mode to instruction flags
436	        const uint8_t play_cmd = [stream_cmd]() -> uint8_t {
437	            switch (stream_cmd.stream_mode) {
438	                case uhd::stream_cmd_t::STREAM_MODE_STOP_CONTINUOUS:
439	                    return PLAY_CMD_STOP; // Stop playing back data
440	                case uhd::stream_cmd_t::STREAM_MODE_NUM_SAMPS_AND_DONE:
441	                case uhd::stream_cmd_t::STREAM_MODE_NUM_SAMPS_AND_MORE:
442	                    return PLAY_CMD_FINITE; // Play NUM_SAMPS then stop
443	                case uhd::stream_cmd_t::STREAM_MODE_START_CONTINUOUS:
444	                    return PLAY_CMD_CONTINUOUS; // Playback continuously over the play
445	                                                // buffer until stopped
446	                default:
447	                    throw uhd::value_error("Requested invalid stream command.");
448	            }
449	        }();
450	
451	        // The register to get the command FIFO space was added in v1.1
452	        if (_fpga_compat >= 0x00010001) {
453	            // Make sure the command queue has space.  Allow stop commands to pass.
454	            if (play_cmd != PLAY_CMD_STOP and _cmd_fifo_spaces[port] == 0) {
455	                _cmd_fifo_spaces[port] =
456	                    _replay_reg_iface.peek32(REG_PLAY_CMD_FIFO_SPACE_ADDR, port);
457	                if (_cmd_fifo_spaces[port] == 0) {
458	                    throw uhd::op_failed("[Replay] Play command queue is full");
459	                }
460	            }
461	        }
462	
463	        // Check the conditions for follow mode
464	        if (_play_follow_mode.at(port).get()) {
465	            if (play_cmd == PLAY_CMD_CONTINUOUS) {
466	                throw uhd::value_error(
467	                    "Follow mode cannot be used with continuous playback.");
468	            }
469	            if (get_record_size(port) < get_play_size(port)) {
470	                throw uhd::value_error("Follow mode cannot be used when play size is "
471	                                       "larger than record size.");
472	            }
473	            if (get_record_offset(port) != get_play_offset(port)) {
474	                throw uhd::value_error("Follow mode cannot be used when play offset and "
475	                                       "record offset are not equal.");
476	            }
477	        }
478	
479	
480	        // Calculate the number of words to transfer in NUM_SAMPS mode
481	        if (play_cmd == PLAY_CMD_FINITE) {
482	            uint64_t num_words =
483	                stream_cmd.num_samps * get_play_item_size(port) / get_word_size();
484	            _replay_reg_iface.poke64(REG_PLAY_CMD_NUM_WORDS_LO_ADDR, num_words, port);
485	        }
486	
487	        // Set the time for the command
488	        const uint32_t timed_flag = (stream_cmd.stream_now) ? 0 : PLAY_COMMAND_TIMED_MASK;
489	        const uint32_t no_eob_flag =
490	            (stream_cmd.stream_mode == uhd::stream_cmd_t::STREAM_MODE_NUM_SAMPS_AND_MORE)
491	                ? PLAY_COMMAND_NO_EOB_MASK
492	                : 0;
493	        const uint32_t follow_mode_flag =
494	            (_play_follow_mode.at(port).get()) ? PLAY_COMMAND_FOLLOW_MODE_MASK : 0;
495	        if (!stream_cmd.stream_now) {
496	            const double tick_rate = get_tick_rate();
497	            UHD_LOG_DEBUG("REPLAY",
498	                "Using tick rate " << (tick_rate / 1e6) << " MHz to set stream command.");
499	            const uint64_t ticks = stream_cmd.time_spec.to_ticks(tick_rate);
500	            _replay_reg_iface.poke64(REG_PLAY_CMD_TIME_LO_ADDR, ticks, port);
501	        }
502	
503	        // Issue the stream command
504	        uint32_t command_word = (play_cmd & PLAY_COMMAND_MASK) | timed_flag | no_eob_flag
505	                                | follow_mode_flag;
506	        _replay_reg_iface.poke32(REG_PLAY_CMD_ADDR, command_word, port);
507	
508	        // The register to get the command FIFO space was added in v1.1
509	        if (_fpga_compat >= 0x00010001) {
510	            if (play_cmd == PLAY_CMD_STOP) {
511	                // The stop command will clear the FIFO, so reset the space value
512	                _cmd_fifo_spaces[port] =
513	                    _replay_reg_iface.peek32(REG_PLAY_CMD_FIFO_SPACE_ADDR, port);
514	            } else {
515	                _cmd_fifo_spaces[port]--;
516	            }
517	        }
518	    }
