540	protected:
541	    // Block-specific register interface
542	    multichan_register_iface _replay_reg_iface;
543	
544	private:
545	    void _register_input_props(const size_t port)
546	    {
547	        // Get default property values
548	        const io_type_t default_type = IO_TYPE_SC16;
549	        const uint64_t record_offset = 0;
550	        const uint64_t record_size   = _mem_size;
551	
552	        // Initialize properties
553	        _record_type.emplace_back(property_t<std::string>(
554	            PROP_KEY_TYPE, default_type, {res_source_info::INPUT_EDGE, port}));
555	        _record_offset.push_back(property_t<uint64_t>(
556	            PROP_KEY_RECORD_OFFSET, record_offset, {res_source_info::USER, port}));
557	        _record_size.push_back(property_t<uint64_t>(
558	            PROP_KEY_RECORD_SIZE, record_size, {res_source_info::USER, port}));
559	        _atomic_item_size_in.push_back(property_t<size_t>(
560	            PROP_KEY_ATOMIC_ITEM_SIZE, _word_size, {res_source_info::INPUT_EDGE, port}));
561	        UHD_ASSERT_THROW(_record_type.size() == port + 1);
562	        UHD_ASSERT_THROW(_record_offset.size() == port + 1);
563	        UHD_ASSERT_THROW(_record_size.size() == port + 1);
564	        UHD_ASSERT_THROW(_atomic_item_size_in.size() == port + 1);
565	
566	        // Register user properties
567	        register_property(&_record_type.at(port));
568	        register_property(&_record_offset.at(port));
569	        register_property(&_record_size.at(port));
570	        register_property(&_atomic_item_size_in.at(port));
571	
572	        // Add property resolvers
573	        add_property_resolver({&_record_offset.at(port)}, {}, [this, port]() {
574	            _set_record_offset(_record_offset.at(port).get(), port);
575	        });
576	        add_property_resolver({&_record_size.at(port)},
577	            {&_record_size.at(port)},
578	            [this, port]() { _set_record_size(_record_size.at(port).get(), port); });
579	        add_property_resolver({&_atomic_item_size_in.back(),
580	                                  get_mtu_prop_ref({res_source_info::INPUT_EDGE, port})},
581	            {&_atomic_item_size_in.back()},
582	            [this, port, &ais_in = _atomic_item_size_in.back()]() {
583	                ais_in = std::lcm<size_t>(ais_in, get_word_size());
584	                ais_in = std::min<size_t>(
585	                    ais_in, get_mtu({res_source_info::INPUT_EDGE, port}));
586	                if (ais_in.get() % get_word_size() > 0) {
587	                    ais_in = ais_in - (ais_in.get() % get_word_size());
588	                }
589	                RFNOC_LOG_TRACE("Resolve atomic item size in to " << ais_in);
590	            });
591	    }
592	
593	    void _register_output_props(const size_t port)
594	    {
595	        // Get default property values
596	        const io_type_t default_type = IO_TYPE_SC16;
597	        const uint64_t play_offset   = 0;
598	        const uint64_t play_size     = _mem_size;
599	        const bool play_follow_mode  = false;
600	        const uint32_t max_payload =
601	            get_max_payload_size({res_source_info::OUTPUT_EDGE, port});
602	        const uint32_t payload_size = max_payload - (max_payload % DEFAULT_MULT);
603	
604	        // Initialize properties
605	        _play_type.emplace_back(property_t<std::string>(
606	            PROP_KEY_TYPE, default_type, {res_source_info::OUTPUT_EDGE, port}));
607	        _play_offset.push_back(property_t<uint64_t>(
608	            PROP_KEY_PLAY_OFFSET, play_offset, {res_source_info::USER, port}));
609	        _play_size.push_back(property_t<uint64_t>(
610	            PROP_KEY_PLAY_SIZE, play_size, {res_source_info::USER, port}));
611	        _play_follow_mode.push_back(property_t<bool>(
612	            PROP_KEY_PLAY_FOLLOW_MODE, play_follow_mode, {res_source_info::USER, port}));
613	        _payload_size.push_back(property_t<uint32_t>(
614	            PROP_KEY_PYLD_SIZE, payload_size, {res_source_info::USER, port}));
615	        _atomic_item_size_out.push_back(property_t<size_t>(
616	            PROP_KEY_ATOMIC_ITEM_SIZE, _word_size, {res_source_info::OUTPUT_EDGE, port}));
617	        UHD_ASSERT_THROW(_play_type.size() == port + 1);
618	        UHD_ASSERT_THROW(_play_offset.size() == port + 1);
619	        UHD_ASSERT_THROW(_play_size.size() == port + 1);
620	        UHD_ASSERT_THROW(_play_follow_mode.size() == port + 1);
621	        UHD_ASSERT_THROW(_payload_size.size() == port + 1);
622	        UHD_ASSERT_THROW(_atomic_item_size_out.size() == port + 1);
623	
624	        // Register user properties
625	        register_property(&_play_type.at(port));
626	        register_property(&_play_offset.at(port));
627	        register_property(&_play_size.at(port));
628	        register_property(&_play_follow_mode.at(port));
629	        register_property(&_payload_size.at(port));
630	        register_property(&_atomic_item_size_out.at(port));
631	
632	        // Add property resolvers
633	        add_property_resolver({&_play_type.at(port)}, {}, [this, port]() {
634	            _set_play_type(_play_type.at(port).get(), port);
635	        });
636	        add_property_resolver({&_play_offset.at(port)}, {}, [this, port]() {
637	            _set_play_offset(_play_offset.at(port).get(), port);
638	        });
639	        add_property_resolver({&_play_size.at(port)},
640	            {&_play_size.at(port)},
641	            [this, port]() { _set_play_size(_play_size.at(port).get(), port); });
642	        add_property_resolver({&_payload_size.at(port),
643	                                  get_mtu_prop_ref({res_source_info::OUTPUT_EDGE, port}),
644	                                  &_atomic_item_size_out.back()},
645	            {&_payload_size.at(port)},
646	            [this, port]() { _set_payload_size(_payload_size.at(port).get(), port); });
647	        add_property_resolver({&_atomic_item_size_out.back(),
648	                                  get_mtu_prop_ref({res_source_info::OUTPUT_EDGE, port})},
649	            {&_atomic_item_size_out.back()},
650	            [this, port, &ais_out = _atomic_item_size_out.back()]() {
651	                ais_out = std::lcm<size_t>(ais_out, get_word_size());
652	                ais_out = std::min<size_t>(
653	                    ais_out, get_mtu({res_source_info::OUTPUT_EDGE, port}));
654	                if (ais_out.get() % get_word_size() > 0) {
655	                    ais_out = ais_out - (ais_out.get() % get_word_size());
656	                }
657	                RFNOC_LOG_TRACE("Resolve atomic item size out to " << ais_out);
658	            });
659	    }
660	
661	    void _set_play_type(const io_type_t type, const size_t port)
662	    {
663	        uint32_t play_item_size = uhd::convert::get_bytes_per_item(type);
664	        _replay_reg_iface.poke32(REG_PLAY_ITEM_SIZE_ADDR, play_item_size, port);
665	    }
666	
667	    void _set_record_offset(const uint64_t record_offset, const size_t port)
668	    {
669	        if ((record_offset % _word_size) != 0) {
670	            throw uhd::value_error("Record offset must be a multiple of word size.");
671	        }
672	        if (record_offset > _mem_size) {
673	            throw uhd::value_error("Record offset is out of bounds.");
674	        }
675	        _replay_reg_iface.poke64(REG_REC_BASE_ADDR_LO_ADDR, record_offset, port);
676	    }
677	
678	    void _set_record_size(const uint64_t record_size, const size_t port)
679	    {
680	        if ((record_size % _word_size) != 0) {
681	            _record_size.at(port) = record_size - (record_size % _word_size);
682	            throw uhd::value_error("Record buffer size must be a multiple of word size.");
683	        }
684	        _replay_reg_iface.poke64(REG_REC_BUFFER_SIZE_LO_ADDR, record_size, port);
685	    }
686	
687	    void _set_play_offset(const uint64_t play_offset, const size_t port)
688	    {
689	        if ((play_offset % _word_size) != 0) {
690	            throw uhd::value_error("Play offset must be a multiple of word size.");
691	        }
692	        if (play_offset > _mem_size) {
693	            throw uhd::value_error("Play offset is out of bounds.");
694	        }
695	        _replay_reg_iface.poke64(REG_PLAY_BASE_ADDR_LO_ADDR, play_offset, port);
696	    }
697	
698	    void _set_play_size(const uint64_t play_size, const size_t port)
699	    {
700	        if ((play_size % _word_size) != 0) {
701	            _play_size.at(port) = play_size - (play_size % _word_size);
702	            throw uhd::value_error("Play buffer size must be a multiple of word size.");
703	        }
704	        if ((play_size % get_play_item_size(port)) != 0) {
705	            _play_size.at(port) = play_size - (play_size % get_play_item_size(port));
706	            throw uhd::value_error("Play buffer size must be a multiple of item size.");
707	        }
708	        _replay_reg_iface.poke64(REG_PLAY_BUFFER_SIZE_LO_ADDR, play_size, port);
709	    }
710	
711	    // This method is only called by the property resolver and coerces the
712	    // property value to a legal value if necessary.
713	    void _set_payload_size(const uint32_t payload_size, const size_t port)
714	    {
715	        const size_t max_pyld_size =
716	            get_max_payload_size({res_source_info::OUTPUT_EDGE, port}, true);
717	        uint32_t new_pyld_size = payload_size;
718	        if (new_pyld_size > max_pyld_size) {
719	            new_pyld_size = max_pyld_size;
720	            RFNOC_LOG_DEBUG("Requested payload size " << payload_size
721	                                                      << " exceeds maximum! Coercing to "
722	                                                      << new_pyld_size);
723	        }
724	
725	        // For correct behavior, we must ensure that the replay payload size is
726	        // a multiple of the:
727	        //   - Replay word size (_word_size)
728	        //   - Atomic item size (e.g., the radio word size)
729	        //   - Configured item size (e.g., sample size)
730	        const uint32_t item_size        = get_play_item_size(port);
731	        const uint32_t atomic_item_size = _atomic_item_size_out.at(port).get();
732	        const uint32_t min_chunk        = std::lcm<uint32_t>(
733	            std::lcm<uint32_t>(item_size, atomic_item_size), _word_size);
734	
735	        if (new_pyld_size % min_chunk != 0) {
736	            const uint32_t coerced_size = new_pyld_size - (new_pyld_size % min_chunk);
737	            RFNOC_LOG_WARNING("Payload size " << new_pyld_size
738	                                              << " is not compatible! Coercing to "
739	                                              << coerced_size);
740	            new_pyld_size = coerced_size;
741	        }
742	        if (new_pyld_size < min_chunk) {
743	            const uint32_t coerced_size = min_chunk;
744	            RFNOC_LOG_WARNING("Payload size " << new_pyld_size
745	                                              << " is too small! Coercing to "
746	                                              << coerced_size);
747	            new_pyld_size = coerced_size;
748	        }
749	
750	        const uint16_t words_per_packet =
751	            uhd::narrow_cast<uint16_t>(new_pyld_size / _word_size);
752	        _replay_reg_iface.poke32(
753	            REG_PLAY_WORDS_PER_PKT_ADDR, uint32_t(words_per_packet), port);
754	
755	        _payload_size.at(port) = new_pyld_size;
756	    }
757	
758	    void _validate_record_buffer(const size_t port)
759	    {
760	        // The entire record buffer must be within the bounds of memory
761	        if ((get_record_offset(port) + get_record_size(port)) > get_mem_size()) {
762	            throw uhd::value_error("Record buffer goes out of bounds.");
763	        }
764	    }
765	
766	    void _validate_play_buffer(const size_t port)
767	    {
768	        // Streaming requires that the buffer size is a multiple of item size
769	        if ((get_play_size(port) % get_play_item_size(port)) != 0) {
770	            throw uhd::value_error("Play size must be must be a multiple of item size.");
771	        }
772	        // The entire play buffer must be within the bounds of memory
773	        if ((get_play_offset(port) + get_play_size(port)) > get_mem_size()) {
774	            throw uhd::value_error("Play buffer goes out of bounds.");
775	        }
776	    }
777	
778	    void _handle_rx_event_action(
779	        const res_source_info& src, rx_event_action_info::sptr rx_event_action)
780	    {
781	        UHD_ASSERT_THROW(src.type == res_source_info::INPUT_EDGE);
782	        uhd::rx_metadata_t rx_md{};
783	        rx_md.error_code = rx_event_action->error_code;
784	        RFNOC_LOG_DEBUG("Received RX error code on channel "
785	                        << src.instance << ", error code " << rx_md.strerror());
786	        _record_msg_queue.push_with_pop_on_full(rx_md);
787	    }
788	
789	    void _handle_tx_event_action(
790	        const res_source_info& src, tx_event_action_info::sptr tx_event_action)
791	    {
792	        UHD_ASSERT_THROW(src.type == res_source_info::OUTPUT_EDGE);
793	
794	        uhd::async_metadata_t md;
795	        md.event_code    = tx_event_action->event_code;
796	        md.channel       = src.instance;
797	        md.has_time_spec = tx_event_action->has_tsf;
798	
799	        if (md.has_time_spec) {
800	            md.time_spec =
801	                uhd::time_spec_t::from_ticks(tx_event_action->tsf, get_tick_rate());
802	        }
803	        RFNOC_LOG_DEBUG("Received TX error code on channel "
804	                        << src.instance << ", error code " << md.strevent());
805	        _playback_msg_queue.push_with_pop_on_full(md);
806	    }
807	
808	    /**************************************************************************
809	     * Attributes
810	     *************************************************************************/
811	    const size_t _num_input_ports;
812	    const size_t _num_output_ports;
813	
814	    // Block compat number
815	    const uint32_t _fpga_compat;
816	
817	    // These size params are configurable in the FPGA
818	    const uint16_t _word_size;
819	    const uint64_t _mem_size;
820	
821	    std::vector<property_t<std::string>> _record_type;
822	    std::vector<property_t<uint64_t>> _record_offset;
823	    std::vector<property_t<uint64_t>> _record_size;
824	    std::vector<property_t<std::string>> _play_type;
825	    std::vector<property_t<uint64_t>> _play_offset;
826	    std::vector<property_t<uint64_t>> _play_size;
827	    std::vector<property_t<bool>> _play_follow_mode;
828	    std::vector<property_t<uint32_t>> _payload_size;
829	    std::vector<property_t<size_t>> _atomic_item_size_in;
830	    std::vector<property_t<size_t>> _atomic_item_size_out;
831	
832	    std::vector<size_t> _cmd_fifo_spaces;
833	
834	    // Message queues for async data
835	    uhd::transport::bounded_buffer<uhd::async_metadata_t> _playback_msg_queue{
836	        ASYNC_MSG_QUEUE_SIZE};
837	    uhd::transport::bounded_buffer<uhd::rx_metadata_t> _record_msg_queue{
838	        ASYNC_MSG_QUEUE_SIZE};
839	};
840	
841	UHD_RFNOC_BLOCK_REGISTER_DIRECT(
842	    replay_block_control, REPLAY_BLOCK, "Replay", CLOCK_KEY_GRAPH, "bus_clk")
843

