1066	void radio_control_impl::issue_stream_cmd(
1067	    const uhd::stream_cmd_t& stream_cmd, const size_t chan)
1068	{
1069	    // std::lock_guard<std::mutex> lock(_mutex);
1070	    RFNOC_LOG_TRACE("radio_control_impl::issue_stream_cmd(chan="
1071	                    << chan << ", mode=" << char(stream_cmd.stream_mode) << ")");
1072	    _last_stream_cmd[chan] = stream_cmd;
1073	
1074	    // calculate the command word
1075	    const std::unordered_map<stream_cmd_t::stream_mode_t, uint32_t, std::hash<size_t>>
1076	        stream_mode_to_cmd_word{
1077	            {stream_cmd_t::STREAM_MODE_START_CONTINUOUS, regmap::RX_CMD_CONTINUOUS},
1078	            {stream_cmd_t::STREAM_MODE_STOP_CONTINUOUS, regmap::RX_CMD_STOP},
1079	            {stream_cmd_t::STREAM_MODE_NUM_SAMPS_AND_DONE, regmap::RX_CMD_FINITE},
1080	            {stream_cmd_t::STREAM_MODE_NUM_SAMPS_AND_MORE, regmap::RX_CMD_FINITE}};
1081	    uint32_t cmd_word = stream_mode_to_cmd_word.at(stream_cmd.stream_mode);
1082	
1083	    if (cmd_word == regmap::RX_CMD_FINITE) {
1084	        if (stream_cmd.num_samps == 0) {
1085	            RFNOC_LOG_WARNING("Ignoring stream command for finite acquisition of "
1086	                              "zero samples");
1087	            return;
1088	        }
1089	        uint64_t num_words               = stream_cmd.num_samps / _spc;
1090	        constexpr uint64_t max_num_words = 0x00FFFFFFFFFFFF; // 48 bits
1091	        if (stream_cmd.num_samps % _spc != 0) {
1092	            num_words++;
1093	            RFNOC_LOG_WARNING("The requested " + std::to_string(stream_cmd.num_samps)
1094	                              + " samples is not a multiple of the samples per cycle ("
1095	                              + std::to_string(_spc) + "); returning "
1096	                              + std::to_string(num_words * _spc) + " samples.");
1097	        }
1098	        if (num_words > max_num_words) {
1099	            RFNOC_LOG_ERROR("Requesting too many samples in a single burst! "
1100	                            "Requested "
1101	                            + std::to_string(stream_cmd.num_samps)
1102	                            + ", maximum "
1103	                              "is "
1104	                            + std::to_string(max_num_words) + "."); // FIXME
1105	            RFNOC_LOG_INFO(
1106	                "Note that a decimation block will increase the number of samples "
1107	                "per burst by the decimation factor. Your application may have "
1108	                "requested fewer samples.");
1109	            throw uhd::value_error("Requested too many samples in a single burst.");
1110	        }
1111	        _radio_reg_iface.poke32(
1112	            regmap::REG_RX_CMD_NUM_WORDS_HI, uint32_t(num_words >> 32), chan);
1113	        _radio_reg_iface.poke32(
1114	            regmap::REG_RX_CMD_NUM_WORDS_LO, uint32_t(num_words & 0xFFFFFFFF), chan);
1115	    }
1116	    if (!stream_cmd.stream_now) {
1117	        switch (stream_cmd.trigger) {
1118	            case stream_cmd_t::trigger_t::TIMED: {
1119	                const uint64_t ticks = stream_cmd.time_spec.to_ticks(get_tick_rate());
1120	                _radio_reg_iface.poke32(
1121	                    regmap::REG_RX_CMD_TIME_HI, uint32_t(ticks >> 32), chan);
1122	                _radio_reg_iface.poke32(
